// Builds the transpose of a graph, which is required for an efficient and
// correct pull-based BFS step on directed graphs.
// This implementation avoids sorting by using parallel prefix sums and atomics.
auto build_transpose(const Graph& G) -> Graph {
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    // Calculate in-degrees for all vertices by iterating over all edges.
    auto in_degrees = parlay::sequence<vertexId>::from_function(n, [](size_t) { return 0; });
    parlay::parallel_for(0, n, [&](size_t u) {
        auto vtx_u = G[u];
        for (size_t i = 0; i < vtx_u.degree; i++) {
            vertexId v = vtx_u.Neighbors[i];
            parlay::internal::atomic_add(&in_degrees[v], 1);
        }
    });

    // Create offsets for the transpose graph from the in-degrees.
    auto new_offsets = parlay::sequence<edgeId>(n + 1);
    new_offsets[0] = 0;
    parlay::scan_into(parlay::make_slice(in_degrees), parlay::make_slice(new_offsets).cut(1, n + 1));

    // A temporary copy of offsets to be used for placing edges concurrently.
    auto temp_offsets = parlay::sequence<edgeId>(n);
    parlay::copy(parlay::make_slice(new_offsets), temp_offsets);

    auto new_edges = parlay::sequence<vertexId>::uninitialized(m);

    // Place the transposed edges into their final positions.
    parlay::parallel_for(0, n, [&](size_t u) {
        auto vtx_u = G[u];
        for (size_t i = 0; i < vtx_u.degree; i++) {
            vertexId v = vtx_u.Neighbors[i];
            edgeId loc = parlay::internal::atomic_fetch_add(&temp_offsets[v], 1);
            new_edges[loc] = u;
        }
    });

    return Graph(std::move(new_offsets), std::move(new_edges), n);
}

// PUSH-based step (for sparse frontiers).
// Iterates over vertices in the frontier and explores their neighbors.
auto edge_map_sparse(const Graph& G,
                     const parlay::sequence<vertexId>& frontier,
                     parlay::sequence<std::atomic<vertexId>>& parent) -> parlay::sequence<vertexId> {

    // Get degrees of all frontier vertices.
    auto degrees = parlay::map(frontier, [&](vertexId u) -> size_t { return G[u].degree; });

    // Calculate total number of neighbors and get offsets for each vertex's
    // neighbors in a flattened output array.
    size_t total_degree = parlay::scan_inclusive_inplace(degrees);
    if (total_degree == 0) return parlay::sequence<vertexId>();

    auto out_edges = parlay::sequence<vertexId>::uninitialized(total_degree);
    auto flags = parlay::sequence<bool>::uninitialized(total_degree);

    // For each vertex in the frontier, try to visit its unvisited neighbors.
    parlay::parallel_for(0, frontier.size(), [&](size_t i) {
        vertexId u = frontier[i];
        auto vtx_u = G[u];
        size_t offset = (i == 0) ? 0 : degrees[i - 1];

        // This inner loop is sequential for better cache performance.
        for (size_t j = 0; j < vtx_u.degree; ++j) {
            vertexId neighbor = vtx_u.Neighbors[j];
            vertexId expected = -1;
            // Attempt to claim the neighbor. A relaxed load is used for the initial
            // check for performance, followed by a stronger compare-and-swap.
            bool success = parent[neighbor].load(std::memory_order_relaxed) == -1 &&
                           parent[neighbor].compare_exchange_strong(expected, u,
                                                                    std::memory_order_release,
                                                                    std::memory_order_relaxed);
            out_edges[offset + j] = neighbor;
            flags[offset + j] = success;
        }
    }, 1); // A grainsize of 1 ensures good load balancing for varied degrees.

    // Pack the successfully visited neighbors to form the new frontier.
    return parlay::pack(out_edges, flags);
}

// PULL-based step (for dense frontiers).
// Unvisited vertices check their in-neighbors to see if any are in the frontier.
auto edge_map_dense(const Graph& GT,
                    const parlay::sequence<bool>& frontier_dense,
                    parlay::sequence<std::atomic<vertexId>>& parent) -> parlay::sequence<bool> {

    size_t n = GT.numVertices();
    // For each vertex v in parallel, check if it can be visited.
    return parlay::tabulate(n, [&](vertexId v) -> bool {
        // If already visited, it cannot be part of the new frontier.
        if (parent[v].load(std::memory_order_relaxed) != -1) {
            return false;
        }

        // Iterate over in-neighbors using the transpose graph.
        auto vtx_v = GT[v];
        for (size_t i = 0; i < vtx_v.degree; ++i) {
            vertexId u = vtx_v.Neighbors[i];
            // If an in-neighbor u is in the current frontier...
            if (frontier_dense[u]) {
                vertexId expected = -1;
                // ...try to claim v.
                if (parent[v].compare_exchange_strong(expected, u,
                                                      std::memory_order_release,
                                                      std::memory_order_relaxed)) {
                    return true; // Successfully claimed, v is in the new frontier.
                } else {
                    // Another thread claimed v just now. Stop trying for v.
                    return false;
                }
            }
        }
        return false; // No parent found in the current frontier.
    });
}


