parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
    parlay::internal::timer t("BFS", verbose);
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    // For the pull phase, we need to iterate over in-edges.
    // Pre-computing the transpose graph is the most efficient way to do this.
    Graph GT = build_transpose(G);
    t.next("Transpose");

    // `parent[i]` stores the parent of vertex `i` in the BFS tree.
    // A value of -1 means unvisited. The root's parent is itself.
    auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) { return -1; });
    parent[start].store(start, std::memory_order_relaxed);

    parlay::sequence<vertexId> frontier_sparse(1, start);
    parlay::sequence<bool> frontier_dense;

    bool is_sparse = true;
    size_t frontier_size = 1;
    long long edges_to_check = G[start].degree;

    // Heuristics for switching between sparse (push) and dense (pull) modes,
    // based on the original Ligra paper.
    const size_t sparse_to_dense_threshold = m / 20;
    const size_t dense_to_sparse_threshold = n / 20;

    while (frontier_size > 0) {
        // Switch from sparse to dense if the frontier and its edges are large.
        if (is_sparse && (frontier_size + edges_to_check > sparse_to_dense_threshold)) {
            is_sparse = false;
            frontier_dense = parlay::sequence<bool>(n, false);
            parlay::parallel_for(0, frontier_sparse.size(), [&](size_t i) {
                frontier_dense[frontier_sparse[i]] = true;
            });
            frontier_sparse.clear(); // Free memory.
            t.next("Switch to dense");
        } 
        // Switch from dense to sparse if the frontier is small.
        else if (!is_sparse && (frontier_size < dense_to_sparse_threshold)) {
            is_sparse = true;
            frontier_sparse = parlay::pack_index<vertexId>(frontier_dense);
            frontier_dense.clear(); // Free memory.
            t.next("Switch to sparse");
        }

        if (is_sparse) {
            // PUSH-based step.
            frontier_sparse = edge_map_sparse(G, frontier_sparse, parent);
            frontier_size = frontier_sparse.size();
            // Update edge count for the next heuristic check.
            if (frontier_size > 0) {
                auto degrees = parlay::delayed_map(frontier_sparse, [&](vertexId u) { return (long long)G[u].degree; });
                edges_to_check = parlay::reduce(degrees);
            }
        } else {
            // PULL-based step.
            frontier_dense = edge_map_dense(GT, frontier_dense, parent);
            frontier_size = parlay::count(frontier_dense, true);
        }
        t.next("Iteration");
    }

    // Convert the atomic parent array to a regular one for output.
    return parlay::map(parent, [](auto const &x) { return x.load(std::memory_order_relaxed); });
}
