/**
 * @brief Computes a Breadth-First Search (BFS) tree for a given graph.
 * 
 * This is a high-performance, parallel, direction-optimizing implementation
 * inspired by the Ligra framework. It starts a BFS from the given `start`
 * vertex and returns a parent tree for all reachable vertices.
 *
 * Key Optimizations:
 * 1. Direction-Optimizing: Switches between a sparse 'push' traversal for small
 *    frontiers and a dense 'pull' traversal for large frontiers, optimizing for
 *    the changing workload characteristics at different stages of the BFS.
 *
 * 2. Optimized Pull Phase: The dense 'pull' phase uses an early-exit strategy.
 *    Once a parent is found for a vertex, the search for other potential parents
 *    for that same vertex is immediately terminated (`break`), significantly
 *    reducing redundant work.
 *
 * 3. Frontier Deduplication: The sparse 'push' phase generates the next frontier
 *    and then uses `parlay::remove_duplicates` to ensure each vertex is processed
 *    only once in the next level, avoiding wasted computation.
 *
 * 4. Relaxed Atomics: Utilizes `std::memory_order_relaxed` for all atomic
 *    operations on the parent array. This reduces synchronization overhead as the
 *    algorithm's correctness only requires atomicity, not strict memory ordering,
 *    which is implicitly handled by the level-synchronous structure.
 *
 * @param start The starting vertex for the BFS.
 * @param G The input graph in adjacency array format.
 * @param verbose If true, prints timing information for each stage.
 * @return A parlay::sequence<vertexId> of length n (number of vertices).
 *         `parent[i]` is the parent of vertex `i` in the BFS tree.
 *         The root's parent is itself. Unreachable vertices have a parent of -1.
 */
parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();

  // parent[i] stores the parent of vertex i in the BFS tree.
  // -1: unvisited.
  // start: root vertex.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n,
      [](size_t) { return -1; });
  parent[start].store(start, std::memory_order_relaxed);
  t.next("init");

  parlay::sequence<vertexId> sparse_frontier(1, start);
  parlay::sequence<bool> dense_frontier;
  bool is_sparse = true;
  size_t frontier_size = 1;

  while (frontier_size > 0) {

    // --- Direction-optimizing heuristic ---
    if (is_sparse) {
      size_t out_degree_sum = parlay::reduce(parlay::delayed_map(sparse_frontier,
          [&](vertexId v) { return G[v].degree; }));
      // Switch to dense pull mode if the frontier is large.
      if ((frontier_size + out_degree_sum) > (G.numEdges() / 20)) {
        is_sparse = false;
        dense_frontier = parlay::sequence<bool>(n, false);
        parlay::parallel_for(0, sparse_frontier.size(), [&](size_t i) {
            dense_frontier[sparse_frontier[i]] = true;
        });
        sparse_frontier.clear();
        t.next("switch_to_dense");
      }
    } else { // is dense
      // Switch back to sparse push mode if the frontier has become small again.
      if (frontier_size < (G.numVertices() / 20)) {
        is_sparse = true;
        sparse_frontier = parlay::pack_index<vertexId>(dense_frontier);
        dense_frontier.clear();
        t.next("switch_to_sparse");
      }
    }

    // --- Process one level of the BFS ---
    if (is_sparse) {
      // --- PUSH PHASE (Sparse Frontier) ---
      auto nested_new_vertices = parlay::map(sparse_frontier, [&](vertexId u) {
        auto vtx = G[u];
        auto neighbors = parlay::make_slice(vtx.Neighbors, vtx.Neighbors + vtx.degree);

        // Try to visit all unvisited neighbors.
        return parlay::filter_map(neighbors, [&](vertexId v) {
            vertexId expected = -1;
            bool success = parent[v].compare_exchange_strong(
                expected, u, std::memory_order_relaxed);
            return success ? std::optional(v) : std::nullopt;
        });
      });

      auto new_frontier_with_dups = parlay::flatten(nested_new_vertices);

      // OPTIMIZATION: Remove duplicates to prevent redundant work in the next level.
      sparse_frontier = parlay::remove_duplicates(new_frontier_with_dups);
      frontier_size = sparse_frontier.size();
      t.next("push");

    } else {
      // --- PULL PHASE (Dense Frontier) ---
      parlay::sequence<bool> next_dense_frontier(n, false);
      parlay::parallel_for(0, n, [&](vertexId v) {
        // If v is unvisited...
        if (parent[v].load(std::memory_order_relaxed) == -1) {
          auto vtx = G[v];
          // ...check its neighbors to see if any are in the current frontier.
          for (size_t i = 0; i < vtx.degree; i++) {
            vertexId u = vtx.Neighbors[i];
            if (dense_frontier[u]) {
              vertexId expected = -1;
              // Try to claim v with parent u.
              if (parent[v].compare_exchange_strong(
                  expected, u, std::memory_order_relaxed)) {
                next_dense_frontier[v] = true;
              }
              // CRITICAL OPTIMIZATION:
              // Whether we succeeded or failed (because another thread claimed v),
              // v is now visited. We can stop checking its neighbors.
              break;
            }
          }
        }
      });
      dense_frontier = std::move(next_dense_frontier);
      frontier_size = parlay::count(dense_frontier, true);
      t.next("pull");
    }
  }

  // Convert atomic parent array to a regular sequence for output.
  return parlay::map(parent, [](auto const &x) {
      return x.load(std::memory_order_relaxed);
  });
}
