namespace {

// Transposes a graph in parallel.
// This is essential for an efficient and correct pull-based BFS on directed graphs.
template <class intV, class intE>
graph<intV, intE> transpose(const graph<intV, intE>& G) {
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    if (m == 0) {
        auto offsets = parlay::sequence<intE>(n + 1, static_cast<intE>(0));
        return graph<intV, intE>(std::move(offsets), parlay::sequence<intV>(), n);
    }

    // 1. Create a flat list of all destination vertices.
    auto all_dests = parlay::sequence<intV>::uninitialized(m);
    parlay::parallel_for(0, n, [&](size_t u) {
        auto v_node = G[u];
        size_t offset = G.get_offsets()[u];
        for (intV i = 0; i < v_node.degree; ++i) {
            all_dests[offset + i] = v_node.Neighbors[i];
        }
    });

    // 2. Count in-degrees for all vertices by creating a histogram of destinations.
    auto in_degrees = parlay::histogram(all_dests, n);

    // 3. Calculate offsets for the transposed graph using a parallel scan.
    auto T_offsets = parlay::sequence<intE>(n + 1);
    T_offsets[0] = 0;
    parlay::scan_inplace(parlay::make_slice(in_degrees), parlay::addm<intE>());
    parlay::parallel_for(0, n, [&](size_t i) { T_offsets[i+1] = in_degrees[i]; });

    // 4. Use atomic counters to place transposed edges correctly.
    auto counters = parlay::sequence<std::atomic<intE>>::from_function(n, [&](size_t i) {
      return T_offsets[i];
    });
    auto T_edges = parlay::sequence<intV>::uninitialized(m);

    parlay::parallel_for(0, n, [&](size_t u) {
        auto v_node = G[u];
        for (intV i = 0; i < v_node.degree; ++i) {
            intV neighbor = v_node.Neighbors[i];
            intE dest_idx = counters[neighbor].fetch_add(1, std::memory_order_relaxed);
            T_edges[dest_idx] = u;
        }
    }, 1); // Use a grainsize of 1 for better load balancing with high-degree vertices

    return graph<intV, intE>(std::move(T_offsets), std::move(T_edges), n);
}

// Represents the BFS frontier, which can be sparse (a list of vertices)
// or dense (a boolean bitmap).
struct Frontier {
    parlay::sequence<vertexId> sparse_q;
    parlay::sequence<bool> dense_q;
    bool is_sparse;
    size_t num_vertices;
    size_t num_graph_vertices;

    Frontier(size_t n) : is_sparse(true), num_vertices(0), num_graph_vertices(n) {}

    void to_sparse() {
        if (is_sparse) return;
        sparse_q = parlay::pack_index<vertexId>(dense_q);
        dense_q.clear();
        is_sparse = true;
    }

    void to_dense() {
        if (!is_sparse) return;
        dense_q = parlay::sequence<bool>(num_graph_vertices, false);
        parlay::parallel_for(0, sparse_q.size(), [&](size_t i) {
            dense_q[sparse_q[i]] = true;
        });
        sparse_q.clear();
        is_sparse = false;
    }

    size_t size() const { return num_vertices; }
    bool empty() const { return num_vertices == 0; }
};

} // anonymous namespace

// **************************************************************
//    FASTEST PARALLEL BFS IMPLEMENTATION
// **************************************************************

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();
  size_t m = G.numEdges();

  // For the pull phase, we need to traverse in-edges.
  // Pre-computing the transpose graph is the most efficient way to do this.
  Graph G_T = transpose(G);
  t.next("Transpose");

  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) { return -1; });
  parent[start] = start;

  Frontier frontier(n);
  frontier.sparse_q = parlay::sequence<vertexId>(1, start);
  frontier.num_vertices = 1;

  // Heuristics to switch between push (sparse) and pull (dense) phases.
  // These are based on well-established values from the Ligra and GAP papers.
  const size_t push_to_pull_threshold_out_edges = m / 20;
  const size_t pull_to_push_threshold_frontier_size = n / 20;

  while (!frontier.empty()) {
    // Decide whether to switch representation
    if (frontier.is_sparse) {
      auto out_degrees = parlay::reduce(parlay::delayed_map(frontier.sparse_q,
                                       [&](vertexId u) { return G[u].degree; }));
      if (frontier.size() + out_degrees > push_to_pull_threshold_out_edges) {
        frontier.to_dense();
        t.next("To Dense");
      }
    } else { // is dense
      if (frontier.size() < pull_to_push_threshold_frontier_size) {
        frontier.to_sparse();
        t.next("To Sparse");
      }
    }

    if (frontier.is_sparse) {
      // PUSH/SPARSE phase: Each vertex in the frontier "pushes" to its neighbors.
      auto visit = [&](vertexId u, vertexId v) {
          vertexId expected = -1;
          return parent[v].compare_exchange_strong(expected, u);
      };

      auto nested_next_frontier = parlay::map(frontier.sparse_q, [&](vertexId u) {
          auto neighbors = G[u];
          auto neighbors_slice = parlay::make_slice(neighbors.Neighbors, neighbors.Neighbors + neighbors.degree);
          // Pre-filter with a non-atomic read to reduce contention on the atomic CAS.
          return parlay::filter(neighbors_slice, [&](vertexId v) {
              return parent[v] == -1 && visit(u, v);
          });
      });

      frontier.sparse_q = parlay::flatten(nested_next_frontier);
      frontier.num_vertices = frontier.sparse_q.size();
      t.next("Push");
    } else {
      // PULL/DENSE phase: Each unvisited vertex "pulls" from its in-neighbors
      // to see if any are in the frontier.
      auto visit = [&](vertexId u, vertexId v) {
          vertexId expected = -1;
          return parent[v].compare_exchange_strong(expected, u);
      };

      auto next_frontier_bools = parlay::tabulate(n, [&](vertexId v) {
          if (parent[v] == -1) {
              auto in_neighbors = G_T[v];
              for (vertexId i = 0; i < in_neighbors.degree; ++i) {
                  vertexId u = in_neighbors.Neighbors[i];
                  if (frontier.dense_q[u]) {
                      if (visit(u, v)) return true;  // Successfully visited
                      // If CAS fails, another thread visited v. We can stop checking for this v.
                      else return false;
                  }
              }
          }
          return false;
      });
      frontier.dense_q = std::move(next_frontier_bools);
      frontier.num_vertices = parlay::count(frontier.dense_q, true);
      t.next("Pull");
    }
  }

  // Convert the atomic parent array to a regular one for the output.
  return parlay::map(parent, [](auto const &x) { return x.load(); });
}
