// **************************************************************
//    Direction-Optimizing Parallel Breadth-First Search
// **************************************************************

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();

  // The parent sequence uses atomics to allow for safe parallel updates.
  // -1 indicates an unvisited vertex.
  // The start vertex is its own parent.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [&](size_t) {
    return -1;
  });
  parent[start] = start;
  t.next("init");

  // fa (function application) tries to claim a vertex `v` for a parent `u`.
  // It uses an atomic compare-and-swap to ensure each vertex is visited only once.
  // It returns true if the claim is successful.
  auto edge_fa = [parents = parent.begin()](vertexId u, vertexId v) -> bool {
    vertexId expected = -1;
    return parents[v].compare_exchange_strong(expected, u);
  };

  // cond (condition) checks if a vertex has been visited.
  auto cond_f = [parents = parent.begin()](vertexId v) { return parents[v] == -1; };

  // The frontier_map encapsulates the traversal logic, switching between
  // sparse and dense modes automatically.
  auto frontier_map = ligra::edge_map(G, edge_fa, cond_f, verbose);

  // The frontier starts with only the source vertex.
  auto frontier = ligra::vertex_subset(start);
  t.next("start");

  // The main loop continues as long as the frontier is not empty.
  while (frontier.size() > 0) {
    frontier = frontier_map(frontier);
    t.next("iter");
  }

  // Convert the atomic parent array to a regular sequence for the output.
  return parlay::map(parent, [](auto const &x) -> vertexId {
    return x.load();
  });
}
