#ifndef LIGRA_LIGHT_H_
#define LIGRA_LIGHT_H_

#include <optional>
#include "parlay/primitives.h"
#include "parlay/parallel.h"
#include "parlay/internal/get_time.h"
#include "parlay/internal/block_delayed.h"
#include "common/graph.h"

namespace delayed = parlay::block_delayed;

namespace ligra {

// Represents the BFS frontier. Can be sparse (a list of vertex IDs)
// or dense (a boolean array).
template <typename vertexId>
struct vertex_subset {
  using sparse_t = parlay::sequence<vertexId>;
  using dense_t = parlay::sequence<bool>;
  bool is_sparse;
  size_t n;
  sparse_t sparse;
  dense_t dense;

  size_t size() const { return n; }

  vertex_subset(sparse_t x)
      : sparse(std::move(x)), is_sparse(true), n(x.size()) {}
  vertex_subset(vertexId v)
      : sparse(sparse_t(1, v)), is_sparse(true), n(1) {}
  vertex_subset(dense_t x)
      : dense(std::move(x)), is_sparse(false),
        n(parlay::count(x, true)) {}
};

// Implements a direction-optimizing edge map operation for graph traversal.
template <typename Graph, typename Fa, typename Cond>
struct edge_map {
  using vertexId = typename Graph::vertexId;
  using vertex_subset_ = vertex_subset<vertexId>;
  using sparse_frontier = parlay::sequence<vertexId>;
  using dense_frontier = parlay::sequence<bool>;

  Fa fa;
  Cond cond;
  const Graph &G;
  bool verbose;

  edge_map(Graph const &G, Fa fa, Cond cond, bool verbose = false)
      : G(G), fa(fa), cond(cond), verbose(verbose) {}

  // PUSH-based traversal for sparse frontiers.
  // Iterates over vertices in the frontier and "pushes" updates to their neighbors.
  auto edge_map_sparse(sparse_frontier const &frontier) {
    if (verbose) std::cout << "edge map sparse (push): " << frontier.size() << std::endl;

    auto nested_edges = parlay::map(frontier, [&](vertexId u) {
      auto vtx_u = G[u];
      // Create a delayed sequence of pairs (parent, child) for edges from u
      return parlay::delayed_tabulate(
          vtx_u.degree,
          [&, u](size_t i) { return std::pair(u, vtx_u.Neighbors[i]); });
    });

    auto edges = delayed::flatten(nested_edges);

    // filter_map returns a delayed sequence of neighbors v for which fa(u, v) succeeded.
    // The atomic CAS in `fa` ensures each vertex's parent is set only once,
    // so the resulting sequence of new frontier vertices is already unique.
    auto next_frontier_delayed = delayed::filter_map(
        edges,
        [&](auto edge) { // Predicate
          auto [u, v] = edge;
          return cond(v) && fa(u, v);
        },
        [](auto edge) { // Map function
          return edge.second;
        });

    // Realize the delayed sequence into a concrete sequence.
    return vertex_subset_(parlay::sequence<vertexId>(next_frontier_delayed));
  }

  // PUSH-based traversal for dense frontiers.
  // A true PULL-based traversal requires in-edges (a transposed graph), which is not
  // available. Therefore, for dense frontiers, we use a dense-push approach.
  // It iterates over all vertices, checks if a vertex is in the dense frontier,
  // and if so, pushes to its neighbors. This is correct for directed graphs
  // and efficient when the frontier is large.
  auto edge_map_dense_push(dense_frontier const &frontier) {
    if (verbose) std::cout << "edge map dense (push): " << parlay::count(frontier, true) << std::endl;
    size_t n = G.numVertices();
    auto next_frontier = parlay::sequence<bool>(n, false);

    parlay::parallel_for(0, n, [&](vertexId u) {
      if (frontier[u]) { // If u is in the current frontier
        auto vtx_u = G[u];
        // Parallelize visiting neighbors for high-degree vertices
        parlay::parallel_for(0, vtx_u.degree, [&](size_t i) {
          vertexId v = vtx_u.Neighbors[i];
          if (cond(v) && fa(u, v)) {
            // A non-atomic write is sufficient due to benign races (true is idempotent).
            if (!next_frontier[v]) {
              next_frontier[v] = true;
            }
          }
        }, 1024); // Use a grain size to avoid overhead on low-degree vertices.
      }
    });
    return vertex_subset_(std::move(next_frontier));
  }

  // Direction-optimizing map function.
  // Switches between sparse-push and dense-push based on frontier size.
  auto operator()(vertex_subset_ const &vtx_subset) {
    parlay::internal::timer t("edge_map", verbose);
    size_t frontier_size = vtx_subset.size();
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    // Heuristics for switching between sparse and dense modes, adapted from GAPBS.
    const size_t alpha = 15;
    const size_t beta = 20;

    if (vtx_subset.is_sparse) {
      // Current frontier is sparse. Decide whether to stay sparse or switch to dense.
      sparse_frontier const &frontier = vtx_subset.sparse;
      if (frontier_size == 0) return vertex_subset_(sparse_frontier());

      auto out_degrees = parlay::delayed_map(frontier, [&](vertexId u) { return G[u].degree; });
      size_t edges_to_visit = parlay::reduce(out_degrees);

      // Switch to dense if work in sparse mode is a significant fraction of total edges.
      if (edges_to_visit > m / alpha) {
        t.next("convert to dense");
        auto d_vtx_subset = parlay::sequence<bool>(n, false);
        parlay::parallel_for(0, frontier.size(),
                             [&](size_t i) { d_vtx_subset[frontier[i]] = true; });
        return edge_map_dense_push(d_vtx_subset);
      } else {
        return edge_map_sparse(frontier);
      }
    } else {
      // Current frontier is dense. Decide whether to stay dense or switch to sparse.
      // Switch back to sparse if the frontier becomes small enough.
      if (frontier_size < n / beta) {
        t.next("convert to sparse");
        return edge_map_sparse(parlay::pack_index<vertexId>(vtx_subset.dense));
      } else {
        return edge_map_dense_push(vtx_subset.dense);
      }
    }
  }
};
} // namespace ligra

#endif // LIGRA_LIGHT_H_
// --- End of file: ligraLight.h ---
