// A structure to represent the frontier, which can be either sparse (a list of vertex IDs)
// or dense (a boolean array). This allows for efficient switching between push and dense-push styles.
struct vertex_subset {
  enum Representation { sparse, dense };
  Representation rep;
  parlay::sequence<vertexId> sparse_v;
  parlay::sequence<bool> dense_v;
  size_t num_vertices;
  size_t n;

  // Create a sparse frontier from a sequence of vertices
  vertex_subset(size_t _num_vertices, parlay::sequence<vertexId>&& vertices)
      : rep(sparse), sparse_v(std::move(vertices)), num_vertices(_num_vertices), n(sparse_v.size()) {}

  // Create a dense frontier from a boolean array and its known size
  vertex_subset(size_t _num_vertices, parlay::sequence<bool>&& flags, size_t count)
      : rep(dense), dense_v(std::move(flags)), num_vertices(_num_vertices), n(count) {}

  size_t size() const { return n; }
  bool is_sparse() const { return rep == sparse; }

  // Convert a sparse frontier to a dense one
  void to_dense() {
    if (rep == dense) return;
    rep = dense;
    parlay::sequence<bool> flags(num_vertices, false);
    parlay::parallel_for(0, n, [&](size_t i) {
      flags[sparse_v[i]] = true;
    });
    dense_v = std::move(flags);
    sparse_v.clear();
    sparse_v.shrink_to_fit();
  }

  // Convert a dense frontier to a sparse one
  void to_sparse() {
    if (rep == sparse) return;
    rep = sparse;
    sparse_v = parlay::pack_index<vertexId>(dense_v);
    dense_v.clear();
    dense_v.shrink_to_fit();
  }
};

// Implements the push-based (sparse) step of the BFS.
// It iterates over the vertices in the current frontier and for each vertex,
// explores its neighbors, attempting to "claim" any unvisited ones.
vertex_subset edge_map_push(const Graph& G, vertex_subset& frontier,
                            parlay::sequence<std::atomic<vertexId>>& parent) {
    auto new_frontier_vertices = parlay::map_flatten(frontier.sparse_v, [&](vertexId u) {
        auto u_vtx = G[u];
        // For each neighbor v of u, try to visit it.
        // map_filter returns a sequence of neighbors v that were successfully visited.
        return parlay::map_filter(parlay::make_slice(u_vtx.Neighbors, u_vtx.Neighbors + u_vtx.degree),
                                  [&](vertexId v) {
            vertexId expected = -1;
            bool claimed = false;
            // Use a relaxed load for a quick check to reduce atomic traffic.
            if (parent[v].load(std::memory_order_relaxed) == expected) {
                // Attempt to claim v for u with a compare-and-swap.
                if (parent[v].compare_exchange_strong(expected, u)) {
                    claimed = true;
                }
            }
            return std::make_pair(claimed, v);
        });
    });
    return vertex_subset(G.numVertices(), std::move(new_frontier_vertices));
}

// Implements a dense-push step of the BFS. This is used when the frontier is large.
// A true "pull" based approach would be more work-efficient but requires the transpose
// of the graph, which is not available. This dense-push approach iterates over all
// vertices in the graph; if a vertex is in the dense frontier, it pushes to its neighbors.
// This is correct and can be faster than a sparse push for large frontiers due to better
// memory access patterns.
vertex_subset edge_map_dense_push(const Graph& G, vertex_subset& frontier,
                                  parlay::sequence<std::atomic<vertexId>>& parent) {
    size_t n = G.numVertices();
    auto next_frontier_flags = parlay::sequence<std::atomic<bool>>::from_function(n, [](size_t){ return false; });

    parlay::parallel_for(0, n, [&](vertexId u) {
        if (frontier.dense_v[u]) {
            auto u_vtx = G[u];
            parlay::parallel_for(0, u_vtx.degree, [&](size_t i) {
                vertexId v = u_vtx.Neighbors[i];
                vertexId expected = -1;
                if (parent[v].load(std::memory_order_relaxed) == expected) {
                    if (parent[v].compare_exchange_strong(expected, u)) {
                        // Atomically set the flag for the next frontier.
                        // A non-atomic write would be a race condition.
                        bool expected_flag = false;
                        next_frontier_flags[v].compare_exchange_strong(expected_flag, true);
                    }
                }
            });
        }
    });

    auto next_dense = parlay::tabulate(n, [&](size_t i) { return next_frontier_flags[i].load(); });
    size_t next_size = parlay::count(next_dense, true);
    return vertex_subset(n, std::move(next_dense), next_size);
}


parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();

  // The parent array stores the BFS tree. `parent[i]` is the parent of vertex `i`.
  // It is atomic to allow for thread-safe updates from multiple threads exploring the graph.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [&](size_t) {
    return -1;
  });
  parent[start] = start;
  t.next("init");

  // The frontier of the BFS.
  vertex_subset frontier(n, parlay::sequence<vertexId>(1, start));

  // Heuristic parameters for switching between push (sparse) and dense-push modes.
  // These are common values from frameworks like Ligra and GAPBS.
  // Switch to dense when the work to check outgoing edges from the frontier is large.
  const size_t push_to_dense_threshold = G.numEdges() / 20;
  // Switch back to sparse when the frontier becomes small again.
  const size_t dense_to_push_threshold = n / 24;

  while (frontier.size() > 0) {
    // Direction optimization: decide whether to use push or dense-push.
    if (frontier.is_sparse()) {
        size_t frontier_size = frontier.size();
        auto out_degrees = parlay::map(frontier.sparse_v, [&](vertexId u) { return G[u].degree; });
        size_t frontier_edges = parlay::reduce(out_degrees);

        if (frontier_size + frontier_edges > push_to_dense_threshold) {
            frontier.to_dense();
            frontier = edge_map_dense_push(G, frontier, parent);
        } else {
            frontier = edge_map_push(G, frontier, parent);
        }
    } else { // Frontier is dense
        if (frontier.size() < dense_to_push_threshold) {
            frontier.to_sparse();
            frontier = edge_map_push(G, frontier, parent);
        } else {
            frontier = edge_map_dense_push(G, frontier, parent);
        }
    }
    t.next("iteration");
  }

  // Convert the atomic parent array to a regular one for the final result.
  return parlay::map(parent, [](auto const &p) { return p.load(); });
}
