```cpp
// BFS.C
// ---
// An optimized parallel Breadth-First Search implementation using ParlayLib.
// This version improves upon the baseline by:
// 1. Implementing a correct direction-optimizing strategy for directed graphs.
// 2. Enabling a fast parallel deduplication of the frontier to prevent redundant work.
// 3. Using well-tuned heuristics for switching between sparse and dense modes.
// 4. Enhancing code structure and adding detailed comments for clarity.

#include <atomic>
#include <limits>
#include "parlay/primitives.h"
#include "parlay/parallel.h"
#include "parlay/sequence.h"
#include "parlay/internal/get_time.h"
#include "parlay/delayed_sequence.h"
#include "common/graph.h"
#include "BFS.h"

// Contains the core parallel primitives for the direction-optimizing BFS.
namespace bfs_helpers {

// Represents the frontier (the set of vertices at the current BFS level).
// Can be in a sparse representation (a list of vertex IDs) for small frontiers,
// or a dense representation (a boolean array) for large frontiers.
template<typename vertexId>
struct vertex_subset {
  using sparse_t = parlay::sequence<vertexId>;
  using dense_t = parlay::sequence<bool>;

  sparse_t sparse_frontier;
  dense_t dense_frontier;
  bool is_sparse;
  size_t n; // Number of vertices in the frontier

  // Construct from a sparse list of vertices
  explicit vertex_subset(sparse_t&& s) :
    sparse_frontier(std::move(s)), is_sparse(true), n(sparse_frontier.size()) {}

  // Construct from a single starting vertex
  vertex_subset(vertexId v) :
    sparse_frontier(parlay::sequence<vertexId>(1, v)), is_sparse(true), n(1) {}

  // Construct from a dense boolean array
  explicit vertex_subset(dense_t&& d) :
    dense_frontier(std::move(d)), is_sparse(false), n(parlay::count(dense_frontier, true)) {}

  size_t size() const { return n; }
};

// The core of the direction-optimizing strategy.
// It takes the current frontier and generates the next one by visiting neighbors.
template<typename Graph, typename F, typename Cond>
auto edge_map(const Graph& G, vertex_subset<typename Graph::vertexId>& current_frontier, F& visit_func, Cond& cond_func) {
  using vertexId = typename Graph::vertexId;
  size_t n = G.numVertices();
  size_t m = G.numEdges();

  // Heuristic parameters for switching between push (sparse) and pull (dense) modes.
  // These values are inspired by the GAP Benchmark Suite and are generally effective.
  // Alpha: controls switch from push to pull. Switch if work > m/alpha.
  const size_t alpha = 14;
  // Beta: controls switch from pull to push. Switch if frontier_size < n/beta.
  const size_t beta = 24;

  size_t frontier_size = current_frontier.size();

  // If the frontier is small, use the PUSH method (sparse traversal).
  if (current_frontier.is_sparse) {
    auto out_degrees = parlay::delayed_seq<size_t>(frontier_size, [&](size_t i) {
      return G[current_frontier.sparse_frontier[i]].degree;
    });
    size_t total_out_degree = parlay::reduce(out_degrees);

    // Heuristic: if the work in push mode (visiting all outgoing edges) is too high,
    // switch to dense representation for the next step.
    if (frontier_size + total_out_degree > m / alpha) {
      auto dense = parlay::tabulate(n, [&](size_t i) { return false; });
      parlay::parallel_for(0, frontier_size, [&](size_t i) {
        dense[current_frontier.sparse_frontier[i]] = true;
      });
      current_frontier = vertex_subset<vertexId>(std::move(dense));
      // Fall through to the dense case below.
    } else {
      // --- Sparse PUSH implementation ---
      auto nested_neighbors = parlay::map(current_frontier.sparse_frontier, [&](vertexId u) {
        auto neighbors = G[u].Neighbors;
        auto degree = G[u].degree;
        // For each neighbor, try to visit it. visit_func returns true on success.
        // We use a delayed sequence to avoid allocating intermediate memory.
        return parlay::delayed_filter_map(parlay::make_slice(neighbors, neighbors + degree),
                                          [&](vertexId v) { return cond_func(v) && visit_func(u, v); },
                                          [&](vertexId v) { return v; });
      });

      auto next_frontier_with_duplicates = parlay::flatten(nested_neighbors);

      // --- Fast Parallel Deduplication ---
      // This is a critical optimization. The next frontier may contain duplicate
      // vertices if multiple vertices in the current frontier visit the same neighbor.
      // This trick removes duplicates in parallel without a full sort.
      auto temp_indices = parlay::sequence<vertexId>::uninitialized(n);
      parlay::parallel_for(0, next_frontier_with_duplicates.size(), [&](size_t i) {
        // Race to write this element's index into a temporary array slot
        // corresponding to its vertex ID. Only one winner per vertex ID.
        temp_indices[next_frontier_with_duplicates[i]] = i;
      });
      auto flags = parlay::tabulate(next_frontier_with_duplicates.size(), [&](size_t i) {
        // The "winner" is the one whose index was successfully written.
        return i == temp_indices[next_frontier_with_duplicates[i]];
      });

      return vertex_subset<vertexId>(parlay::pack(next_frontier_with_duplicates, flags));
    }
  }

  // If the frontier is large, use the DENSE PUSH method.
  // Heuristic: if the frontier becomes small again, switch back to sparse.
  if (frontier_size < n / beta) {
    auto sparse = parlay::pack_index<vertexId>(current_frontier.dense_frontier);
    current_frontier = vertex_subset<vertexId>(std::move(sparse));
    // Recurse/retry with the new sparse representation. This happens at most once per level.
    return edge_map(G, current_frontier, visit_func, cond_func);
  } else {
    // --- Dense PUSH implementation ---
    // This is a "pull-style" loop over all vertices, but it performs a "push"
    // from frontier vertices. It is correct for directed graphs without needing
    // the transpose graph.
    auto next_frontier_flags = parlay::sequence<std::atomic<bool>>::from_function(n, [](size_t){ return false; });
    parlay::parallel_for(0, n, [&](vertexId u) {
      if (current_frontier.dense_frontier[u]) {
        auto neighbors = G[u].Neighbors;
        auto degree = G[u].degree;
        parlay::parallel_for(0, degree, [&](size_t i) {
          vertexId v = neighbors[i];
          if (cond_func(v) && visit_func(u, v)) {
            // If visit is successful, mark v for the next frontier.
            // Use atomic CAS to handle concurrent writes.
            bool expected = false;
            next_frontier_flags[v].compare_exchange_strong(expected, true, std::memory_order_relaxed);
          }
        });
      }
    });
    auto next_dense_frontier = parlay::tabulate(n, [&](size_t i) { return next_frontier_flags[i].load(); });
    return vertex_subset<vertexId>(std::move(next_dense_frontier));
  }
}

} // namespace bfs_helpers


