parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();

  // The parent array stores the BFS tree. `parent[i]` is the parent of vertex `i`.
  // It is atomic to allow for thread-safe concurrent updates from multiple threads
  // visiting the same vertex simultaneously.
  // -1 represents an unvisited vertex. The start vertex is its own parent.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) { return -1; });
  parent[start] = start;
  t.next("init");

  // The function to be applied to an edge (u, v) where u is in the frontier.
  // It atomically attempts to claim v, setting its parent to u.
  // It returns true if the claim was successful, false otherwise.
  auto visit_func = [&](vertexId u, vertexId v) -> bool {
    vertexId expected = -1;
    return parent[v].compare_exchange_strong(expected, u);
  };

  // A pre-condition check to quickly filter out already-visited vertices.
  // This reduces contention on the atomic `parent` array.
  auto cond_func = [&](vertexId v) { return parent[v] == -1; };

  // The initial frontier contains only the start vertex.
  auto frontier = bfs_helpers::vertex_subset<vertexId>(start);
  t.next("start");

  // Main BFS loop: process levels as long as the frontier is not empty.
  while (frontier.size() > 0) {
    frontier = bfs_helpers::edge_map(G, frontier, visit_func, cond_func);
    t.next("iter");
  }

  // Convert the atomic parent array to a regular sequence for the output.
  return parlay::map(parent, [](auto const &x) { return x.load(); });
}
