// --- Start of file: ligraLight.h ---
#ifndef PBBS_LIGRA_LIGHT_H_
#define PBBS_LIGRA_LIGHT_H_

#include <limits>
#include <iostream>
#include "parlay/primitives.h"
#include "parlay/parallel.h"
#include "parlay/internal/get_time.h"
#include "parlay/internal/block_delayed.h"
#include "common/graph.h"

namespace delayed = parlay::block_delayed;

namespace ligra {

// A memory-efficient packed bitvector for representing dense vertex subsets.
// Reduces memory footprint by 8x compared to sequence<bool>, improving cache performance.
struct bitvector {
  size_t n;
  parlay::sequence<long> data;

  bitvector(size_t n=0) : n(n), data(n/64 + 1, 0) {}

  // Check if bit i is set
  bool get(size_t i) const {
    return (data[i/64] >> (i % 64)) & 1L;
  }

  // Set bit i (not atomic)
  void set(size_t i) {
    data[i/64] |= (1L << (i % 64));
  }

  // Count the number of set bits in parallel
  size_t count() const {
    auto counts = parlay::map(data, [] (long val) {
      return __builtin_popcountl(val);
    });
    return parlay::reduce(counts);
  }
};

// Represents a subset of vertices, can be sparse (a list) or dense (a bitvector).
template<typename vertexId>
struct vertex_subset {
  using sparse_t = parlay::sequence<vertexId>;
  using dense_t = bitvector;

  bool is_sparse;
  size_t n;         // Number of vertices in the graph
  size_t s;         // Number of vertices in the subset
  sparse_t sparse;
  dense_t dense;

  vertex_subset(size_t n, vertexId v) :
    is_sparse(true), n(n), s(1), sparse(sparse_t(1,v)), dense(0) {}

  vertex_subset(size_t n, sparse_t&& x) :
    is_sparse(true), n(n), s(x.size()), sparse(std::move(x)), dense(0) {}

  vertex_subset(size_t n, dense_t&& x) :
    is_sparse(false), n(n), dense(std::move(x)) {
      s = dense.count();
  }

  // Constructor from a boolean sequence (result of dense edge_map)
  vertex_subset(size_t n, const parlay::sequence<bool>& bool_seq) :
    is_sparse(false), n(n), dense(n) {
      parlay::parallel_for(0, n, [&] (size_t i) {
        if (bool_seq[i]) dense.set(i);
      });
      s = parlay::count(bool_seq, true);
  }

  size_t size() const { return s; }
};

// The core direction-optimizing map over edges incident to the frontier.
template<typename Graph, typename Fa, typename Cond>
struct edge_map {
  using vertexId = typename Graph::vertexId;
  using vertex_subset_ = vertex_subset<vertexId>;
  using sparse_t = typename vertex_subset_::sparse_t;
  using dense_t = typename vertex_subset_::dense_t;

  Fa fa;
  Cond cond;
  const Graph& G;
  bool dedup;
  bool verbose;

  edge_map(Graph const &G, Fa fa, Cond cond, bool dedup=false, bool verbose=false) :
    G(G), fa(fa), cond(cond), dedup(dedup), verbose(verbose) {}

  // Push-based implementation for sparse frontiers
  auto edge_map_sparse(const sparse_t& vtx_subset) {
    if (verbose) std::cout << "edge map sparse: " << vtx_subset.size() << std::endl;
    auto nested_edges = parlay::map(vtx_subset, [&] (vertexId v) {
      return parlay::delayed_tabulate(G[v].degree, [&, v] (size_t i) {
        return std::pair(v, G[v].Neighbors[i]);
      });
    });
    auto edges = delayed::flatten(nested_edges);
    auto r = delayed::filter_map(edges,
      [&] (auto x) { return cond(x.second) && fa(x.first, x.second); },
      [] (auto x) { return x.second; });

    // Deduplication is disabled by default as atomics in `fa` handle correctness,
    // and the cost of processing a few duplicates is often less than deduplication.
    if (dedup) {
      return vertex_subset_(G.numVertices(), parlay::unique(parlay::sort(r)));
    }
    return vertex_subset_(G.numVertices(), std::move(r));
  }

  // Pull-based implementation for dense frontiers (using the bitvector)
  auto edge_map_dense(const dense_t& vtx_subset) {
    if (verbose) std::cout << "edge map dense: " << vtx_subset.size() << std::endl;
    auto r = parlay::tabulate(G.numVertices(), [&](vertexId v) -> bool {
      bool result = false;
      if (cond(v)) {
        auto vtx = G[v];
        auto ngh = vtx.Neighbors;
        auto d = vtx.degree;
        // For high-degree vertices, parallelize the check over neighbors
        if (d > 2048) {
          size_t block_size = 2048;
          size_t num_blocks = (d + block_size - 1) / block_size;
          parlay::parallel_for(0, num_blocks, [&](size_t i) {
            if (result || !cond(v)) return;
            size_t start = i * block_size;
            size_t end = std::min(start + block_size, d);
            for (size_t j = start; j < end; j++) {
              vertexId u = ngh[j];
              if (vtx_subset.get(u)) {
                if (fa(u,v)) {
                  result = true;
                  break;
                }
              }
            }
          }, 1); // low grainsize for inner loop
        } else { // Sequential check for lower-degree vertices
          for (size_t j = 0; j < d; j++) {
            vertexId u = ngh[j];
            if (vtx_subset.get(u)) { // Check against the bitvector
              if (fa(u,v)) {
                result = true;
                break;
              }
            }
          }
        }
      }
      return result;
    });
    return vertex_subset_(G.numVertices(), r);
  }

  // Main operator that implements the direction-optimizing heuristic
  auto operator() (vertex_subset_ const &vtx_subset) {
    parlay::internal::timer t("edge_map", verbose);
    size_t n = G.numVertices();
    size_t m = G.numEdges();
    size_t frontier_size = vtx_subset.size();

    if (vtx_subset.is_sparse) {
      // Heuristic to switch from sparse (push) to dense (pull)
      auto out_degree = parlay::reduce(parlay::delayed_map(vtx_subset.sparse, [&](size_t i) {
        return G[i].degree;
      }));
      if ((frontier_size + out_degree) > m / 20) {
        dense_t d_vtx_subset(n);
        parlay::parallel_for(0, frontier_size, [&](size_t i) {
          d_vtx_subset.set(vtx_subset.sparse[i]);
        });
        t.next("convert to dense");
        return edge_map_dense(d_vtx_subset);
      } else {
        return edge_map_sparse(vtx_subset.sparse);
      }
    } else {
      // Heuristic to switch from dense (pull) to sparse (push)
      if (frontier_size < n / 20) {
        // Convert bitvector to sparse sequence
        const auto& dense_data = vtx_subset.dense.data;
        auto counts = parlay::map(dense_data, [] (long val) { return __builtin_popcountl(val); });
        auto offsets = parlay::scan_inclusive(counts, parlay::addm<size_t>());
        auto s_vtx_subset = sparse_t::uninitialized(offsets.back());
        parlay::parallel_for(0, dense_data.size(), [&](size_t i) {
            long word = dense_data[i];
            if (word == 0) return;
            size_t offset = (i == 0) ? 0 : offsets[i-1];
            size_t k = 0;
            while (word != 0) {
                int j = __builtin_ctzl(word);
                s_vtx_subset[offset + k++] = i * 64 + j;
                word &= word - 1; // clear lowest set bit
            }
        });
        t.next("convert to sparse");
        return edge_map_sparse(s_vtx_subset);
      } else {
        return edge_map_dense(vtx_subset.dense);
      }
    }
  }
};
