// Implements one step of the BFS, visiting neighbors of the current frontier.
// Switches between sparse (top-down) and dense (bottom-up) modes automatically.
template <typename G, typename VisitFn, typename ConditionFn>
struct EdgeMap {
  using VtxId = typename G::vertexId;
  using VtxSubset = VertexSubset<VtxId>;

  const G& graph;
  VisitFn visit_fn;      // Function to attempt visiting a vertex.
  ConditionFn cond_fn;   // Function to check if a vertex is unvisited.

  // Heuristics from the Ligra paper for switching between sparse and dense modes.
  // These values are known to work well across a wide range of graph types.
  static constexpr long alpha = 20; // Switch to dense when frontier + out-edges > m/alpha
  static constexpr long beta = 20;  // Switch to sparse when frontier < n/beta

  EdgeMap(const G& g, VisitFn f, ConditionFn c)
      : graph(g), visit_fn(f), cond_fn(c) {}

  // Top-Down (sparse) step: iterate over the frontier and "push" to neighbors.
  VtxSubset edge_map_sparse(const parlay::sequence<VtxId>& frontier) {
    // Create a delayed representation of all outgoing edges from the frontier
    auto nested_edges = parlay::map(frontier, [&](VtxId u) {
      return parlay::delayed_tabulate(graph[u].degree, [&, u](size_t i) {
        return std::make_pair(u, graph[u].Neighbors[i]);
      });
    });
    auto edges = parlay::block_delayed::flatten(nested_edges);

    // Filter the edges to find neighbors that are unvisited, and attempt to visit them.
    // The visit_fn (using an atomic CAS) ensures each vertex is visited only once.
    // The result 'r' is a sequence of newly visited vertices.
    // The CAS in visit_fn guarantees the output is already deduplicated.
    auto r = parlay::block_delayed::filter_map(
        edges,
        [&](const auto& edge) {
          return cond_fn(edge.second) && visit_fn(edge.first, edge.second);
        },
        [](const auto& edge) { return edge.second; });

    return VtxSubset(graph.numVertices(), std::move(r));
  }

  // Bottom-Up (dense) step: iterate over all unvisited vertices and "pull" from the frontier.
  VtxSubset edge_map_dense(const parlay::sequence<bool>& frontier) {
    size_t n = graph.numVertices();
    auto next_frontier = parlay::sequence<bool>(n);

    parlay::parallel_for(0, n, [&](size_t v) {
      // For each vertex 'v', check if it's unvisited.
      if (cond_fn(v)) {
        auto vtx = graph[v];
        auto d = vtx.degree;
        if (d > 0) {
          auto ngh = vtx.Neighbors;
          // In parallel, check if any neighbor 'u' is in the current frontier.
          // The inner parallel_for uses a grainsize to avoid overhead on low-degree vertices.
          parlay::parallel_for(
              0, d,
              [&](size_t i) {
                // Early exit: if another thread has already found a parent for 'v', stop.
                if (!cond_fn(v)) return;
                VtxId u = ngh[i];
                if (frontier[u]) {
                  visit_fn(u, v); // Attempt to claim 'v'. If successful, cond_fn(v) becomes false.
                }
              }, 1024);
        }
        // If 'v' was unvisited at the start and is now visited, add it to the next frontier.
        next_frontier[v] = !cond_fn(v);
      } else {
        next_frontier[v] = false;
      }
    });

    return VtxSubset(n, std::move(next_frontier));
  }

  // Main operator that selects the appropriate mode (sparse or dense).
  VtxSubset operator()(const VtxSubset& frontier) {
    size_t n = graph.numVertices();
    size_t m = graph.numEdges();
    size_t frontier_size = frontier.size();

    if (frontier_size == 0) {
      return VtxSubset(n, parlay::sequence<VtxId>());
    }

    if (frontier.is_sparse) {
      // From sparse, decide whether to stay sparse or switch to dense.
      auto out_degree_delayed = parlay::delayed_map(
          frontier.sparse_frontier, [&](VtxId v) { return (size_t)graph[v].degree; });
      size_t out_degree = parlay::reduce(out_degree_delayed);

      if ((frontier_size + out_degree) > m / alpha) {
        // Switch to dense representation and run the dense step
        auto dense_f = parlay::sequence<bool>(n, false);
        parlay::parallel_for(0, frontier_size,
                             [&](size_t i) { dense_f[frontier.sparse_frontier[i]] = true; });
        return edge_map_dense(dense_f);
      } else {
        // Stay sparse
        return edge_map_sparse(frontier.sparse_frontier);
      }
    } else {  // Is dense
      // From dense, decide whether to stay dense or switch back to sparse.
      if (frontier_size < n / beta) {
        // Switch back to sparse representation and run the sparse step
        auto sparse_f = parlay::pack_index<VtxId>(frontier.dense_frontier);
        return edge_map_sparse(sparse_f);
      } else {
        // Stay dense
        return edge_map_dense(frontier.dense_frontier);
      }
    }
  }
};

