/**
 * @brief Performs a parallel Breadth-First Search on a graph.
 *
 * This function implements a direction-optimizing (hybrid) BFS, which is the
 * state-of-the-art for shared-memory parallel BFS. It dynamically switches
 * between a top-down (sparse frontier) and bottom-up (dense frontier)
 * approach for optimal performance.
 *
 * @param start The starting vertex for the BFS.
 * @param G The input graph in adjacency array format.
 * @param verbose If true, prints timing information.
 * @return A sequence representing the BFS parent tree. For each vertex, it
 *         contains the ID of its parent. The root's parent is itself.
 *         Unreachable vertices have a parent of -1.
 */
parlay::sequence<vertexId> BFS(vertexId start, const Graph& G,
                               bool verbose = false) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();

  // The parent array stores the BFS tree. We use atomics for thread-safe updates.
  // -1 indicates an unvisited vertex.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(
      n, [](size_t) { return -1; });
  parent[start] = start;
  t.next("init");

  // The visit function attempts to claim an unvisited vertex `v` for a parent `u`.
  // It uses an atomic compare-and-swap to guarantee each vertex is visited once.
  auto visit_fn = [&](vertexId u, vertexId v) -> bool {
    vertexId expected = -1;
    return parent[v].compare_exchange_strong(expected, u);
  };

  // The condition function checks if a vertex has been visited.
  auto cond_fn = [&](vertexId v) { return parent[v] == -1; };

  // The EdgeMap functor encapsulates the logic for one step of the BFS.
  internal::EdgeMap<Graph, decltype(visit_fn), decltype(cond_fn)> edge_map(
      G, visit_fn, cond_fn);

  // Initialize the frontier with the start vertex.
  internal::VertexSubset<vertexId> frontier(n, start);
  t.next("start");

  // Main BFS loop: process frontiers until no new vertices are discovered.
  while (frontier.size() > 0) {
    frontier = edge_map(frontier);
    t.next("iter");
  }

  // Convert the atomic parent array to a regular sequence for the output.
  return parlay::map(parent, [](const auto& x) { return x.load(); });
}
