          parlay::parallel_for(0, vtx.degree, [&](size_t i) {
            vertexId v = vtx.Neighbors[i];
            vertexId expected = -1;
            // If `v` is unvisited, claim it and mark it for the next frontier.
            if (parents[v].compare_exchange_strong(expected, u)) {
              next_frontier_flags[v] = true;
            }
          });
        }
      });

      // The new frontier is all vertices that were successfully claimed.
      // Convert the atomic flags back to a regular boolean sequence for the next dense iteration.
      dense_frontier = parlay::map(next_frontier_flags, [](auto const& b){ return b.load(); });

      // We still need a sparse representation to check if the frontier is empty.
      // `pack_index` is highly efficient for this conversion.
      frontier = parlay::pack_index<vertexId>(dense_frontier);
    }
  }

  // Convert the result from std::atomic<vertexId> to vertexId for the output.
  return parlay::map(parents, [](auto const &x) {
    return x.load();
  });
}
