// Helper function to build the transpose of a graph.
// This is essential for an efficient and correct pull-step in BFS on directed graphs.
// The transpose graph G_T has an edge u->v for every edge v->u in the original graph G.
Graph transpose_graph(const Graph& G) {
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    // 1. Count in-degrees for all vertices in parallel to determine memory layout.
    auto in_degrees = parlay::sequence<std::atomic<edgeId>>::uninitialized(n);
    parlay::parallel_for(0, n, [&](size_t i) { in_degrees[i] = 0; });

    parlay::parallel_for(0, n, [&](size_t u) {
        auto u_vtx = G[u];
        for (size_t i = 0; i < u_vtx.degree; ++i) {
            vertexId v = u_vtx.Neighbors[i];
            in_degrees[v].fetch_add(1, std::memory_order_relaxed);
        }
    });

    // 2. Compute the offsets for the transpose graph using a parallel scan.
    auto offsets_T = parlay::sequence<edgeId>(n + 1);
    offsets_T[0] = 0;
    parlay::scan_inplace(parlay::map(in_degrees, [](auto const& a) { return a.load(); }),
                         parlay::make_slice(offsets_T).drop_front(1),
                         parlay::addm<edgeId>());

    // 3. Populate the edges array of the transpose graph in parallel.
    // Each thread uses an atomic counter to find where to write its edges.
    auto edges_T = parlay::sequence<vertexId>(m);
    auto write_counters = parlay::map(parlay::make_slice(offsets_T).drop_last(1), 
                                      [](edgeId o){ return std::atomic<edgeId>(o); });

    parlay::parallel_for(0, n, [&](size_t u) {
        auto u_vtx = G[u];
        for (size_t i = 0; i < u_vtx.degree; ++i) {
            vertexId v = u_vtx.Neighbors[i];
            // Edge u->v in G becomes edge v->u in G_T.
            edgeId pos = write_counters[v].fetch_add(1, std::memory_order_relaxed);
            edges_T[pos] = u;
        }
    });

    return Graph(std::move(offsets_T), std::move(edges_T), n);
}

