parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();

  // Parent array stores the BFS tree. -1 indicates an unvisited vertex.
  // Atomics are used for safe parallel updates from multiple threads.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) { return -1; });
  parent[start] = start;
  t.next("init");

  parlay::sequence<vertexId> frontier(1, start);

  // Transpose graph, lazily initialized only if we enter pull mode.
  std::optional<Graph> G_T;

  // Heuristics for switching between push and pull modes.
  const size_t alpha = 15; // Switch back to push when frontier is small
  const size_t beta = 18;  // Switch to pull when frontier work is large

  bool in_pull_mode = false;

  while (!frontier.empty()) {
    if (in_pull_mode) {
        // Currently in PULL mode. Check if we should switch back to PUSH.
        if (frontier.size() < n / alpha) {
            if (verbose) cout << "Switching to Push: frontier_size = " << frontier.size() << endl;
            in_pull_mode = false;
        }
    } else {
        // Currently in PUSH mode. Check if we should switch to PULL.
        size_t frontier_work = parlay::reduce(parlay::delayed_map(frontier, [&](vertexId u) { return G[u].degree; }))
                               + frontier.size();
        if (frontier_work > G.numEdges() / beta) {
            if (verbose) cout << "Switching to Pull: frontier_work = " << frontier_work << endl;
            in_pull_mode = true;
        }
    }

    if (in_pull_mode) {
      // --- PULL STEP (Dense Frontier) ---
      // For each unvisited vertex `v`, check its in-neighbors `u` to see if any are in the frontier.
      if (!G_T) {
        G_T.emplace(transpose_graph(G));
        t.next("transpose");
      }

      auto frontier_flags = parlay::sequence<bool>(n, false);
      parlay::parallel_for(0, frontier.size(), [&](size_t i) {
        frontier_flags[frontier[i]] = true;
      });
      t.next("frontier_to_dense");

      auto is_newly_visited = parlay::tabulate(n, [&](size_t v) -> bool {
        if (parent[v].load(std::memory_order_relaxed) == -1) {
          auto v_vtx_T = (*G_T)[v];
          auto in_neighbors = parlay::make_slice(v_vtx_T.Neighbors, v_vtx_T.Neighbors + v_vtx_T.degree);

          // Find the first in-neighbor that is in the frontier.
          auto it = parlay::find_if(in_neighbors, [&](vertexId u) { return frontier_flags[u]; });

          if (it != in_neighbors.end()) {
            vertexId u_parent = *it;
            vertexId expected = -1;
            // Atomically claim `v`. If successful, it's a new vertex.
            if (parent[v].compare_exchange_strong(expected, u_parent)) {
              return true;
            }
          }
        }
        return false;
      });
      t.next("pull_kernel");

      frontier = parlay::pack_index<vertexId>(is_newly_visited);
      t.next("pack");

    } else {
      // --- PUSH STEP (Sparse Frontier) ---
      // For each vertex `u` in the frontier, visit its unvisited out-neighbors `v`.
      auto nested_new_vertices = parlay::map(frontier, [&](vertexId u) {
        auto u_vtx = G[u];
        auto neighbors = parlay::make_slice(u_vtx.Neighbors, u_vtx.Neighbors + u_vtx.degree);

        return parlay::map(neighbors, [&](vertexId v) {
          vertexId expected = -1;
          // Quick check to avoid expensive atomic if already visited.
          if (parent[v].load(std::memory_order_relaxed) == -1 &&
              parent[v].compare_exchange_strong(expected, u)) {
