      t.next("push_kernel");

      frontier = parlay::filter(new_vertices_with_sentinels, [](vertexId v) { return v != -1; });
      t.next("pack");
    }
  }

  // Convert atomic parent array to a regular sequence for the final result.
  return parlay::map(parent, [](auto const& p) { return p.load(); });
}
