// Helper function to compute the transpose of a graph in parallel.
// The transpose graph G_T contains an edge (v, u) for every edge (u, v) in G.
// This is necessary for an efficient and correct pull-based BFS phase on directed graphs.
template<typename Graph>
Graph transpose(const Graph& G) {
    using vertexId = typename Graph::vertexId;
    using edgeId = typename Graph::edgeId;
    size_t n = G.numVertices();

    // Count in-degrees for each vertex in parallel.
    auto in_degrees = parlay::sequence<edgeId>(n, (edgeId)0);
    parlay::parallel_for(0, n, [&](vertexId u) {
        auto vtx = G[u];
        for (edgeId i = 0; i < vtx.degree; ++i) {
            vertexId v = vtx.Neighbors[i];
            parlay::write_add(&in_degrees[v], 1);
        }
    });

    // Compute offsets for the transpose graph's edge array using a parallel scan.
    auto offsets = parlay::sequence<edgeId>(n + 1);
    parlay::scan_inclusive_inplace(parlay::make_slice(in_degrees), parlay::addm<edgeId>());
    offsets[0] = 0;
    parlay::parallel_for(0, n, [&](size_t i) { offsets[i+1] = in_degrees[i]; });

    size_t m = offsets[n];
    auto edges = parlay::sequence<vertexId>::uninitialized(m);

    // A temporary copy of offsets to track current insertion points for each vertex.
    auto current_offsets = parlay::sequence<edgeId>(n);
    parlay::parallel_for(0, n, [&](size_t i) { current_offsets[i] = offsets[i]; });

    // Place edges in the transpose graph in parallel.
    parlay::parallel_for(0, n, [&](vertexId u) {
        auto vtx = G[u];
        for (edgeId i = 0; i < vtx.degree; ++i) {
            vertexId v = vtx.Neighbors[i];
            edgeId new_pos = parlay::fetch_and_add(&current_offsets[v], 1);
            edges[new_pos] = u;
        }
    });

    return Graph(std::move(offsets), std::move(edges), n);
}


