  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [&] (size_t i) {
      return -1;});
  parent[start] = start;

  // Function to be applied to an edge (u, v):
  // Atomically check if v is unvisited (-1) and, if so, set its parent to u.
  auto edge_fa = [iparent=parent.begin()] (vertexId u, vertexId v) -> bool {
    vertexId expected = -1;
    return iparent[v].compare_exchange_strong(expected, u);
  };

  // Condition function: returns true if a vertex has not been visited.
  auto cond_f = [iparent=parent.begin()] (vertexId v) { return iparent[v] == -1;};

  // The edge_map object encapsulates the direction-optimizing logic.
  // We pass both G (for push) and G_T (for pull).
  auto frontier_map = ligra::edge_map(G, G_T, edge_fa, cond_f, false, verbose);

