  // Iterates over vertices in the frontier and pushes to their neighbors.
  // This implementation generates a duplicate-free next frontier.
  auto edge_map_sparse(vertex_subset_sparse const &vtx_subset) {
    if (verbose) std::cout << "edge map sparse (push): " << vtx_subset.size() << std::endl;
    auto nested_successors = parlay::map(vtx_subset, [&](vertexId u) {
        auto vtx = G_out[u];
        auto neighbors = parlay::make_slice(vtx.Neighbors, vtx.Neighbors + vtx.degree);

        // For each neighbor v, try to visit it (fa(u,v)).
        // map_filter collects only the neighbors that were successfully visited.
        return parlay::map_filter(neighbors, [&](vertexId v) -> std::optional<vertexId> {
            if (cond(v) && fa(u, v)) {
                return {v};
            }
            return std::nullopt;
        });
    });
    // The result is already deduplicated because fa will only succeed once per vertex v.
    return vertex_subset_(parlay::flatten(nested_successors));
  }

  // PULL-based traversal for dense frontiers.
  // Iterates over all unvisited vertices and checks if any in-neighbor is in the frontier.
  // Uses the transpose graph G_in for efficiency.
  auto edge_map_dense(vertex_subset_dense const &vtx_subset) {
    if (verbose) std::cout << "edge map dense (pull): " << parlay::count(vtx_subset, true) << std::endl;
    auto r = parlay::tabulate(G_in.numVertices(), [&](vertexId v) -> bool {
        if (cond(v)) { // If v is unvisited
            auto vtx = G_in[v]; // Use transpose graph to get IN-NEIGHBORS
            auto in_neighbors = parlay::make_slice(vtx.Neighbors, vtx.Neighbors + vtx.degree);

            // Parallel search for an in-neighbor `u` that is in the current frontier.
            auto it = parlay::find_if(in_neighbors, [&](vertexId u) {
                return vtx_subset[u];
            });

            // If a parent `u` is found in the frontier, try to claim `v`.
            if (it != in_neighbors.end()) {
                vertexId u = *it;
                if (fa(u, v)) {
                    return true;
                }
            }
        }
        return false;
    });
    return vertex_subset_(std::move(r));
  }

  auto operator() (vertex_subset_ const &vtx_subset) {
    parlay::internal::timer t("edge_map", verbose);
    size_t l = vtx_subset.size();
    size_t n = G_out.numVertices();
    if (vtx_subset.is_sparse) {
      auto out_degree = parlay::reduce(parlay::delayed_map(vtx_subset.sparse, [&] (size_t i) {
			   return G_out[i].degree;}));
      // Heuristic: switch to dense PULL mode if frontier is large.
      if ((l + out_degree) > G_out.m/20) {
	      parlay::sequence<bool> d_vtx_subset(n, false);
	      parlay::parallel_for(0, l, [&] (size_t i) {
          d_vtx_subset[vtx_subset.sparse[i]] = true;});
	      t.next("convert to dense");
	      return edge_map_dense(d_vtx_subset);
      } else return edge_map_sparse(vtx_subset.sparse);
    } else {
      // Heuristic: switch back to sparse PUSH mode if frontier becomes small again.
      if (l > n/20) return edge_map_dense(vtx_subset.dense);
      else {
	      auto s_vtx_subset = parlay::pack_index<vertexId>(vtx_subset.dense);
        t.next("convert to sparse");
	      return edge_map_sparse(s_vtx_subset);
      }
    }
  }
};
