// This is a corrected and optimized implementation based on the
// provided ligraLight.h, tailored for maximum performance.
namespace bfs_helpers {

template<typename vertexId>
struct vertex_subset {
  using sparse_t = parlay::sequence<vertexId>;
  using dense_t = parlay::sequence<bool>;
  bool is_sparse;
  size_t n;
  sparse_t sparse;
  dense_t dense;

  // Constructor for a sparse frontier
  explicit vertex_subset(sparse_t x) :
    sparse(std::move(x)), is_sparse(true), n(sparse.size()) {}

  // Constructor for a sparse frontier with a single vertex
  explicit vertex_subset(vertexId v) :
    sparse(parlay::sequence<vertexId>(1,v)), is_sparse(true), n(1) {}

  // Constructor for a dense frontier
  explicit vertex_subset(dense_t x) :
    dense(std::move(x)), is_sparse(false),
    n(parlay::count(dense, true)) {}

  size_t size() const { return n; }
};

// The core engine for applying a function over edges from a frontier.
// It implements the direction-optimizing strategy.
template<typename Graph, typename Fa, typename Cond> 
struct edge_map {
  using vertexId = typename Graph::vertexId;
  using edgeId = typename Graph::edgeId;
  using vertex_subset_ = vertex_subset<vertexId>;
  using sparse_frontier_ = parlay::sequence<vertexId>;
  using dense_frontier_ = parlay::sequence<bool>;

  Fa fa;
  Cond cond;
  const Graph& G;
  Graph TG; // Transpose Graph for pull-based traversal
  bool has_transpose;
  bool verbose;

  // Transposes the graph G. This is needed for an efficient and correct
  // pull-based traversal on directed graphs.
  static Graph transpose(const Graph& G, bool verbose) {
    parlay::internal::timer t("BFS (transpose)", verbose);
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    // 1. Count in-degrees for each vertex to determine offsets.
    parlay::sequence<edgeId> counts(n, 0);
    parlay::parallel_for(0, n, [&](size_t u) {
        for (edgeId i = G.offsets[u]; i < G.offsets[u+1]; i++) {
            parlay::internal::atomic_add(&counts[G.edges[i]], 1);
        }
    });
    t.next("count");

    // 2. Compute offsets from counts (exclusive scan).
    parlay::sequence<edgeId> t_offsets(n + 1);
    t_offsets[0] = 0;
    parlay::scan_into(counts, t_offsets.cut(1, n + 1));
    t.next("scan");

    // 3. Write the transposed edges.
    parlay::sequence<vertexId> t_edges = parlay::sequence<vertexId>::uninitialized(m);
    auto current_offsets = t_offsets; // Make a mutable copy for atomic increments
    parlay::parallel_for(0, n, [&](size_t u) {
        for (edgeId i = G.offsets[u]; i < G.offsets[u+1]; i++) {
            vertexId v = G.edges[i];
            edgeId loc = parlay::internal::atomic_fetch_add(&current_offsets[v], 1);
            t_edges[loc] = u;
        }
    }, 1); // Use grainsize 1 for better load balancing on skewed-degree graphs.
    t.next("write");

    return Graph(std::move(t_offsets), std::move(t_edges), n);
  }

  edge_map(Graph const &G, Fa fa, Cond cond, bool verbose=false) :
    G(G), fa(fa), cond(cond), has_transpose(false), verbose(verbose) {}

  // PUSH-based traversal: iterate over the sparse frontier and "push"
  // updates to neighbors. Efficient for small frontiers.
  auto edge_map_sparse(sparse_frontier_ const &frontier) {
    if (verbose) std::cout << "edge map sparse (push): " << frontier.size() << std::endl;

    auto nested_out_vertices = parlay::map(frontier, [&](vertexId u) {
        auto v_obj = G[u];
        auto neighbors = parlay::make_slice(v_obj.Neighbors, v_obj.Neighbors + v_obj.degree);

        // For each neighbor, check the condition and apply the update function.
        // Return the neighbor if the update was successful.
        auto new_neighbors = parlay::map(neighbors, [&](vertexId v) {
            if (cond(v) && fa(u, v)) return v;
            return static_cast<vertexId>(-1); // Sentinel for unsuccessful visit
        });

        // Pack the successfully visited neighbors into the result.
        return parlay::pack(new_neighbors, parlay::delayed_map(new_neighbors, 
                              [](vertexId v) { return v != -1; }));
    });

    return vertex_subset_(parlay::flatten(nested_out_vertices));
  }

  // PULL-based traversal: iterate over all unvisited vertices and "pull"
  // updates from neighbors in the frontier. Efficient for large frontiers.
  auto edge_map_dense(dense_frontier_ const &frontier) {
    if (verbose) std::cout << "edge map dense (pull): " << parlay::count(frontier, true) << std::endl;

    // Lazily compute transpose graph on the first call.
    if (!has_transpose) {
        TG = transpose(G, verbose);
        has_transpose = true;
    }

    auto next_frontier_dense = parlay::tabulate(G.numVertices(), [&](vertexId v) -> bool {
        if (cond(v)) {
            auto in_vtx = TG[v];
            // Check in-neighbors to see if any are in the current frontier.
            for (size_t i = 0; i < in_vtx.degree; ++i) {
                vertexId u = in_vtx.Neighbors[i];
                if (frontier[u]) {
                    // Found a parent in the frontier. Try to visit `v`.
                    // If successful, `v` is in the next frontier. If not, another
                    // thread just visited it, so it's also in the next frontier.
                    // In either case, we can stop checking neighbors for `v`.
                    if (fa(u, v)) return true;
                    else return true;
                }
            }
        }
        return false;
    });
    return vertex_subset_(std::move(next_frontier_dense));
  }

  // Main operator that decides whether to PUSH or PULL.
  auto operator() (vertex_subset_ const &frontier) {
    parlay::internal::timer t("BFS (edge_map)", verbose);
    size_t frontier_size = frontier.size();
    size_t n = G.numVertices();

    if (frontier.is_sparse) {
      auto out_degree = parlay::reduce(parlay::delayed_map(frontier.sparse, [&](size_t i) {
          return G[i].degree;
      }));
      // Heuristic: switch to pull if frontier and its edges are "large".
      if ((frontier_size + out_degree) > n / 20) {
        dense_frontier_ d_frontier(n, false);
        parlay::parallel_for(0, frontier_size, [&] (size_t i) {
          d_frontier[frontier.sparse[i]] = true;
        });
        t.next("convert to dense");
        return edge_map_dense(d_frontier);
      } else {
        return edge_map_sparse(frontier.sparse);
      }
    } else { // Frontier is dense
      // Heuristic: switch back to push if frontier becomes "small" again.
      if (frontier_size < n / 25) {
        auto s_frontier = parlay::pack_index<vertexId>(frontier.dense);
        t.next("convert to sparse");
        return edge_map_sparse(s_frontier);
      } else {
        return edge_map_dense(frontier.dense);
      }
    }
  }
};
} // namespace bfs_helpers


