parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();

  // The parent array stores the BFS tree. `std::atomic` is used for safe
  // concurrent updates from multiple threads. -1 indicates an unvisited vertex.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [] (size_t) {
      return static_cast<vertexId>(-1);
  });
  parent[start] = start; // The root of the BFS tree points to itself.

  // The update function: tries to atomically set the parent of `v` to `u`.
  // Returns true on success (i.e., `v` was unvisited).
  auto edge_update_func = [iparent=parent.begin()] (vertexId u, vertexId v) -> bool {
    vertexId expected = -1;
    return iparent[v].compare_exchange_strong(expected, u, std::memory_order_relaxed);
  };

  // The condition function: checks if a vertex has been visited.
  auto visit_cond_func = [iparent=parent.begin()] (vertexId v) {
      return iparent[v] == -1;
  };

  // Create the direction-optimizing edge map operator.
  auto frontier_map = bfs_helpers::edge_map(G, edge_update_func, visit_cond_func, verbose);

  // The frontier starts with just the source vertex.
  auto frontier = bfs_helpers::vertex_subset(start);
  t.next("setup");

  // Run the BFS level by level until the frontier is empty.
  while (frontier.size() > 0) {
    frontier = frontier_map(frontier);
    t.next("iteration");
  }

  // Convert the final atomic parent array to a regular sequence for output.
  return parlay::map(parent, [] (auto const &x) -> vertexId {
      return x.load();
  });
}
