graph<vertexId, edgeId> transpose(const Graph& G, bool verbose) {
    parlay::internal::timer t("Transpose", verbose);
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    // 1. Count degrees for each vertex in the transpose graph
    auto degrees = parlay::sequence<edgeId>(n, (edgeId)0);
    parlay::parallel_for(0, n, [&](size_t u) {
        auto u_vtx = G[u];
        for (size_t i = 0; i < u_vtx.degree; ++i) {
            vertexId v = u_vtx.Neighbors[i];
            parlay::write_add(&degrees[v], 1);
        }
    });
    t.next("Count Degrees");

    // 2. Compute the offsets for the transpose graph's edge array (exclusive scan)
    auto offsets = parlay::sequence<edgeId>(n + 1);
    parlay::scan_into(degrees, parlay::make_slice(offsets).subseq(1, n + 1));
    offsets[0] = 0;
    t.next("Scan");

    // 3. Populate the edge array of the transpose graph
    auto edges = parlay::sequence<vertexId>::uninitialized(m);
    auto counts = offsets.copy(); // Use a copy for thread-safe concurrent writes

    parlay::parallel_for(0, n, [&](size_t u) {
        auto u_vtx = G[u];
        for (size_t i = 0; i < u_vtx.degree; ++i) {
            vertexId v = u_vtx.Neighbors[i];
            edgeId loc = parlay::fetch_and_add(&counts[v], 1);
            edges[loc] = u;
        }
    });
    t.next("Populate Edges");

    return graph<vertexId, edgeId>(std::move(offsets), std::move(edges), n);
}


parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
  parlay::internal::timer t("BFS", verbose);

  // For the bottom-up step to work correctly on directed graphs, we need the
  // graph with incoming edges, i.e., the transpose of G.
  Graph GT = transpose(G, verbose);
  t.next("Transpose");

  size_t n = G.numVertices();
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [] (size_t i) {
      return -1;});
  parent[start] = start;

  // The edge function attempts to claim an unvisited vertex `v` for parent `u`.
  // It uses an atomic compare-and-swap to ensure only one parent is assigned.
  auto edge_fa = [iparent=parent.begin()] (vertexId u, vertexId v) -> bool {
    vertexId expected = -1;
    return iparent[v].compare_exchange_strong(expected, u);
  };

  // The condition function checks if a vertex has been visited.
  auto cond_f = [iparent=parent.begin()] (vertexId v) { return iparent[v] == -1;};

  // The edge_map object encapsulates the direction-optimizing logic.
  // It now takes both G and its transpose GT.
  auto frontier_map = ligra::edge_map(G, GT, edge_fa, cond_f, verbose);

  auto frontier = ligra::vertex_subset(start);
  t.next("Initialize");

  while (frontier.size() > 0) {
    frontier = frontier_map(frontier);
    t.next("Iteration");
  }

  // Convert the atomic parent array to a regular one for the output.
  return parlay::map(parent, [] (auto const &x) -> vertexId {
      return x.load();});
}

