// **************************************************************
//    GRAPH TRANSPOSE UTILITY
// **************************************************************
// Takes a graph in CSR format and returns its transpose.
// This is essential for an efficient and correct pull-based (backward) BFS step.
Graph transpose(const Graph& G) {
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    // Create a list of edges represented as (destination, source) pairs.
    auto transposed_edge_list = parlay::sequence<std::pair<vertexId, vertexId>>::uninitialized(m);
    parlay::parallel_for(0, n, [&](size_t u) {
        edgeId offset = G.get_offsets()[u];
        auto vtx = G[u];
        parlay::parallel_for(0, vtx.degree, [&](size_t i) {
            vertexId v = vtx.Neighbors[i];
            transposed_edge_list[offset + i] = {v, u};
        });
    });

    // Sort edges by the new source vertex (which was the original destination).
    // This groups all in-edges for each vertex together.
    parlay::sort_inplace(transposed_edge_list);

    // Build the CSR representation (offsets and edges) for the transposed graph.
    auto t_offsets = parlay::sequence<edgeId>::uninitialized(n + 1);
    auto t_edges = parlay::sequence<vertexId>::uninitialized(m);

    // Identify the start of each vertex's adjacency list in the sorted edge list
    // and extract the new destination vertices.
    parlay::parallel_for(0, m, [&](size_t i) {
        t_edges[i] = transposed_edge_list[i].second;
        if (i == 0 || transposed_edge_list[i].first != transposed_edge_list[i-1].first) {
            t_offsets[transposed_edge_list[i].first] = i;
        }
    });
    t_offsets[n] = m;

    // Fill in offsets for vertices that have an in-degree of 0.
    // This parallel scan propagates the last valid offset forward.
    parlay::scan_inclusive_inplace(t_offsets, parlay::maxm<edgeId>());

    return Graph(std::move(t_offsets), std::move(t_edges), n);
}


// **************************************************************
//    HIGH-PERFORMANCE DIRECTION-OPTIMIZING BFS
// **************************************************************

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
    parlay::internal::timer t("BFS", verbose);
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    // The parent array stores the BFS tree. `std::atomic` is crucial for safe
    // concurrent updates in the push phase. Initialized to -1 (unvisited).
    auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) { return -1; });
    parent[start] = start;
    t.next("init");

    // The frontier of the BFS search.
    parlay::sequence<vertexId> frontier_sparse(1, start);
    size_t frontier_size = 1;
    bool is_sparse = true; // Start in sparse (push) mode.

    // A dense representation of the frontier, used for the pull phase.
    parlay::sequence<bool> frontier_dense;

    // The transposed graph is created lazily only when needed for the first pull phase.
    std::unique_ptr<Graph> G_T = nullptr;

    // Heuristics to switch between push (sparse) and pull (dense) modes.
    const size_t push_to_pull_threshold_m = m / 20;
    const size_t pull_to_push_threshold_n = n / 20;

    while (frontier_size > 0) {
        // --- Direction-optimization: Decide whether to PUSH or PULL ---
        if (is_sparse) {
            edgeId frontier_degree = parlay::reduce(parlay::map(frontier_sparse, [&](vertexId u) {
                return static_cast<edgeId>(G[u].degree);
            }));
            if (frontier_size + frontier_degree > push_to_pull_threshold_m) {
                // Switch to dense (pull) mode
                is_sparse = false;
                frontier_dense = parlay::sequence<bool>(n, false);
                parlay::parallel_for(0, frontier_sparse.size(), [&](size_t i) {
                    frontier_dense[frontier_sparse[i]] = true;
                });
            }
        } else { // is_dense
            if (frontier_size < pull_to_push_threshold_n) {
                // Switch to sparse (push) mode
                is_sparse = true;
                frontier_sparse = parlay::pack_index<vertexId>(frontier_dense);
            }
        }
        t.next("decision");

        if (is_sparse) {
            // --- PUSH phase (sparse frontier) ---
            // For each vertex in the frontier, "push" its parent to its unvisited neighbors.
            auto nested_new_frontiers = parlay::map(frontier_sparse, [&](vertexId u) {
                auto vtx = G[u];
                // Filter for neighbors that are unvisited and successfully claim them.
                return parlay::filter(parlay::make_slice(vtx.Neighbors, vtx.Neighbors + vtx.degree),
                                      [&](vertexId v) {
                    vertexId expected = -1;
                    return parent[v].compare_exchange_strong(expected, u, std::memory_order_relaxed);
                });
            });

            frontier_sparse = parlay::flatten(nested_new_frontiers);

            // Deduplicate the new frontier to ensure each vertex is processed once per level.
            if (frontier_sparse.size() > 1) {
              parlay::sort_inplace(frontier_sparse);
              frontier_sparse = parlay::unique(frontier_sparse);
            }
            frontier_size = frontier_sparse.size();
            t.next("push");

        } else {
            // --- PULL phase (dense frontier) ---
            // Each unvisited vertex "pulls" a parent from the current frontier.

            // Lazily create the transposed graph if it doesn't exist.
            if (G_T == nullptr) {
                G_T = std::make_unique<Graph>(transpose(G));
                t.next("transpose");
            }

            auto next_frontier_dense = parlay::sequence<bool>(n, false);

            parlay::parallel_for(0, n, [&](vertexId u) {
                // If u is unvisited, check its in-neighbors (i.e., neighbors in G_T).
                if (parent[u].load(std::memory_order_relaxed) == -1) {
                    auto vtx_t = (*G_T)[u];
                    for (size_t i = 0; i < vtx_t.degree; ++i) {
                        vertexId v = vtx_t.Neighbors[i];
                        if (frontier_dense[v]) { // If an in-neighbor `v` is in the current frontier...
                            // ...claim `u` with `v` as parent.
                            // Since we parallelize over `u`, no other thread will write to `parent[u]`.
                            // Thus, we can use a fast, non-atomic store.
                            parent[u].store(v, std::memory_order_relaxed);
                            next_frontier_dense[u] = true;
                            break; // Found a parent, can stop searching for `u`.
                        }
                    }
                }
            });

            frontier_dense = std::move(next_frontier_dense);
            frontier_size = parlay::count(frontier_dense, true);
            t.next("pull");
        }
    }

    // Convert the atomic parent array to a regular sequence for the output.
    return parlay::map(parent, [](auto const &x) { return x.load(); });
}
