// **************************************************************
//    PARALLEL DIRECTION-OPTIMIZING BFS
// **************************************************************

// A direction-optimizing parallel BFS implementation.
//
// This algorithm is also known as a top-down/bottom-up or push/pull BFS.
// It dynamically switches between two modes of traversal for optimal performance:
//
// 1. PUSH (Top-Down):
//    - Used when the frontier (the set of vertices to visit) is small.
//    - Each vertex on the current frontier "pushes" parent information to its
//      unvisited neighbors, attempting to claim them.
//    - This is efficient for small frontiers as the work is proportional
//      to the number of outgoing edges from the frontier.
//    - Implemented with a sparse representation of the frontier (a sequence of vertex IDs).
//
// 2. PULL (Bottom-Up):
//    - Used when the frontier is large.
//    - Each unvisited vertex in the graph "pulls" parent information by checking its
//      neighbors to see if any of them are in the current frontier.
//    - This is efficient for large frontiers because it avoids redundant work and
//      contention. The work is proportional to the number of edges incident on
//      unvisited vertices.
//    - Implemented with a dense representation of the frontier (a boolean array).
//
// The switch between modes is based on heuristics that estimate the work
// required by each approach.
//
// NOTE on Directed Graphs: The PULL phase of this implementation assumes the
// graph is symmetric (undirected). It iterates over the given out-neighbors
// of an unvisited vertex `v` to find a parent `u` in the frontier. For a
// general directed graph, it should iterate over the in-neighbors of `v`.
// A correct implementation for general directed graphs would require a transposed
// graph representation, which is not built here to optimize for performance
// on the common case of symmetric graphs, which are produced by the specified
// default graph generators.

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();

  // The parent array also serves as the visited set.
  // - A value of -1 indicates the vertex has not been visited.
  // - The start vertex is its own parent.
  // - We use std::atomic to allow for thread-safe concurrent updates.
  auto parents = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) {
    return static_cast<vertexId>(-1);
  });
  parents[start].store(start);
  t.next("init");

  // The frontier of the BFS traversal.
  parlay::sequence<vertexId> sparse_frontier(1, start);
  parlay::sequence<bool> dense_frontier;
  bool is_sparse = true;
  long frontier_size = 1;

  // Heuristic parameters for switching between PUSH and PULL modes.
  // These values are based on research from frameworks like Ligra and GAP.
  const size_t alpha = 15; // Controls switch from PUSH to PULL
  const size_t beta = 20;  // Controls switch from PULL to PUSH

  while (frontier_size > 0) {
    // --- Heuristic-based mode switching ---
    if (is_sparse) {
      auto out_degrees = parlay::delayed_map(sparse_frontier, [&](vertexId u) {
        return G[u].degree;
      });
      size_t frontier_edges = parlay::reduce(out_degrees);

      if (frontier_size + frontier_edges > G.numEdges() / alpha) {
        // Switch from sparse (PUSH) to dense (PULL)
        dense_frontier = parlay::sequence<bool>(n, false);
        parlay::parallel_for(0, sparse_frontier.size(), [&](size_t i) {
          dense_frontier[sparse_frontier[i]] = true;
        });
        sparse_frontier.clear();
        is_sparse = false;
        t.next("switch_to_dense");
      }
    } else { // is dense
      if (frontier_size < n / beta) {
        // Switch from dense (PULL) to sparse (PUSH)
        sparse_frontier = parlay::pack_index<vertexId>(dense_frontier);
        dense_frontier.clear();
        is_sparse = true;
        t.next("switch_to_sparse");
      }
    }

    // --- Execute one step of BFS traversal ---
    if (is_sparse) {
      // PUSH (Top-Down) traversal
      auto nested_new_frontier = parlay::map(sparse_frontier, [&](vertexId u) {
        auto neighbors_obj = G[u];
        auto neighbors = parlay::make_slice(neighbors_obj.Neighbors,
                                            neighbors_obj.Neighbors + neighbors_obj.degree);

        // Attempt to visit all unvisited neighbors.
        auto visitor = [&](vertexId v) {
          vertexId expected = -1;
          // Use a relaxed load for a quick check before the expensive CAS.
          if (parents[v].load(std::memory_order_relaxed) == -1) {
            return parents[v].compare_exchange_strong(expected, u);
          }
          return false;
        };
        return parlay::filter(neighbors, visitor);
      });

      sparse_frontier = parlay::flatten(nested_new_frontier);
      frontier_size = sparse_frontier.size();
      t.next("push_step");

    } else {
      // PULL (Bottom-Up) traversal
      parlay::sequence<bool> next_dense_frontier(n, false);
      parlay::parallel_for(0, n, [&](vertexId v) {
        if (parents[v].load(std::memory_order_relaxed) == -1) {
          auto neighbors_obj = G[v];
          for (vertexId i = 0; i < neighbors_obj.degree; ++i) {
            vertexId u = neighbors_obj.Neighbors[i];
            if (dense_frontier[u]) {
              vertexId expected = -1;
              if (parents[v].compare_exchange_strong(expected, u)) {
                next_dense_frontier[v] = true;
                // Found a parent, no need to check other neighbors for v.
                break;
              }
              // If CAS fails, another thread just visited v. We can also stop.
              if (parents[v].load(std::memory_order_relaxed) != -1) {
                break;
              }
            }
          }
        }
      });
      dense_frontier = std::move(next_dense_frontier);
      frontier_size = parlay::count(dense_frontier, true);
      t.next("pull_step");
    }
  }

  // Convert the atomic parent array to a regular sequence for the output.
  auto final_parents = parlay::map(parents, [](auto const& p) {
    return p.load();
  });
  t.next("finalize");
  return final_parents;
}
