namespace delayed = parlay::block_delayed;

namespace ligra {

template<typename vertexId>
struct vertex_subset {
  using sparse_t = parlay::sequence<vertexId>;
  using dense_t = parlay::sequence<bool>;
  bool is_sparse;
  size_t n;
  sparse_t sparse;
  dense_t dense;

  // Constructor for a sparse subset
  vertex_subset(sparse_t x) : is_sparse(true), n(x.size()), sparse(std::move(x)) {}

  // Constructor for a single-vertex subset
  vertex_subset(vertexId v) : is_sparse(true), n(1), sparse(parlay::sequence<vertexId>(1, v)) {}

  // Constructor for a dense subset
  vertex_subset(dense_t x) : is_sparse(false), n(parlay::count(x, true)), dense(std::move(x)) {}

  size_t size() const { return n; }
};

template<typename Graph, typename Fa, typename Cond> 
struct edge_map {
  using vertexId = typename Graph::vertexId;
  using vertex_subset_ = vertex_subset<vertexId>;
  using vertex_subset_sparse = parlay::sequence<vertexId>;
  using vertex_subset_dense = parlay::sequence<bool>;

  const Graph& G;
  Fa fa;
  Cond cond;
  bool verbose;

  edge_map(Graph const &G, Fa fa, Cond cond, bool verbose=false) :
    G(G), fa(fa), cond(cond), verbose(verbose) {}

  // Top-down (push) step for a sparse frontier.
  auto edge_map_sparse(vertex_subset_sparse const &vtx_subset) {
    if (verbose) std::cout << "edge_map_sparse: frontier_size = " << vtx_subset.size() << std::endl;

    auto nested_edges = parlay::map(vtx_subset, [&](vertexId u) {
      auto vtx_u = G[u];
      // Create a delayed sequence of neighbors for vertex u
      return parlay::delayed_tabulate(vtx_u.degree, [=](size_t i) {
        return std::pair(u, vtx_u.Neighbors[i]);
      });
    });

    auto edges = delayed::flatten(nested_edges);

    // For each edge (u, v), if cond(v) is true, apply fa(u, v).
    // Return a new sparse frontier of vertices v for which fa returned true.
    auto new_frontier_with_duplicates = delayed::filter_map(edges,
      [&](auto edge) { return cond(edge.second) && fa(edge.first, edge.second); },
      [](auto edge) { return edge.second; });

    // Remove duplicates to form the final new frontier.
    return vertex_subset_(parlay::remove_duplicates(new_frontier_with_duplicates));
  }

  // EXPERT IMPLEMENTATION:
  // This is a corrected and optimized "dense push" implementation.
  // The original baseline had an incorrect "dense pull" that did not work for directed graphs.
  // This version iterates over all vertices `u`. If `u` is in the current dense frontier,
  // it "pushes" updates to its neighbors `v`, ensuring correctness and high performance.
  auto edge_map_dense(vertex_subset_dense const &vtx_subset) {
    size_t num_active = parlay::count(vtx_subset, true);
    if (verbose) std::cout << "edge_map_dense (push): frontier_size = " << num_active << std::endl;
    size_t n = G.numVertices();

    // The next frontier is built into an atomic boolean array to allow
    // thread-safe concurrent writes.
    auto next_frontier = parlay::sequence<std::atomic<bool>>::from_function(n, [](size_t){ return false; });

    // For each vertex `u` in the graph...
    parlay::parallel_for(0, n, [&](vertexId u) {
      // ...if `u` is in the current frontier...
      if (vtx_subset[u]) {
        auto vtx_u = G[u];
        // ...push to all its neighbors `v`.
        for (size_t i = 0; i < vtx_u.degree; i++) {
          vertexId v = vtx_u.Neighbors[i];
          // `cond(v)` checks if v is unvisited. `fa(u, v)` atomically attempts to
          // set parent[v] = u. It returns true only on the first successful visit.
          if (cond(v) && fa(u, v)) {
            // If successful, mark `v` as part of the next frontier.
            // A relaxed store is sufficient as we only need atomicity, not memory ordering.
            next_frontier[v].store(true, std::memory_order_relaxed);
          }
        }
      }
    });

    // Convert the atomic bool array back to a regular bool array.
    // This also serves as a synchronization point before the next BFS level.
    auto result_dense = parlay::map(next_frontier, [](const auto& a){ return a.load(); });
    return vertex_subset_(std::move(result_dense));
  }

  // The main operator that implements the direction-optimizing strategy.
  auto operator() (vertex_subset_ const &vtx_subset) {
    parlay::internal::timer t("edge_map", verbose);
    size_t frontier_size = vtx_subset.size();
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    // Heuristic to switch from sparse (top-down) to dense (bottom-up/dense-push).
    // Switch to dense if the frontier is large enough.
    if (vtx_subset.is_sparse) {
      auto out_degrees = parlay::delayed_map(vtx_subset.sparse, [&](size_t i) { return G[i].degree; });
      size_t frontier_edges = parlay::reduce(out_degrees);

      // Ligra's heuristic: switch if the work in the sparse step (visiting vertices and edges
      // in the frontier) exceeds a fraction of the total graph edges.
      if ((frontier_size + frontier_edges) > m / 20) {
        // Convert sparse frontier to dense and run dense step
        parlay::sequence<bool> d_vtx_subset(n, false);
        parlay::parallel_for(0, frontier_size, [&](size_t i) {
          d_vtx_subset[vtx_subset.sparse[i]] = true;
        });
        t.next("convert_to_dense");
        return edge_map_dense(d_vtx_subset);
      } else {
        return edge_map_sparse(vtx_subset.sparse);
      }
    } else { // Frontier is already dense
      // Heuristic to switch back from dense to sparse if the frontier becomes small again.
      if (frontier_size < n / 20) {
        // Convert dense frontier to sparse and run sparse step
        auto s_vtx_subset = parlay::pack_index<vertexId>(vtx_subset.dense);
        t.next("convert_to_sparse");
        return edge_map_sparse(s_vtx_subset);
      } else {
        return edge_map_dense(vtx_subset.dense);
      }
    }
  }
};

