/**
 * @brief Computes the Breadth-First Search tree for a given graph and start vertex.
 * 
 * This implementation uses a highly parallel, direction-optimizing algorithm.
 * It dynamically switches between a sparse "push" traversal and a dense "push"
 * traversal based on the size of the BFS frontier for optimal performance.
 * 
 * @param start The starting vertex for the BFS.
 * @param G The input graph in adjacency array format.
 * @param verbose If true, prints timing information for each step.
 * @return A sequence of parent pointers representing the BFS tree. For each vertex `i`,
 *         the value at index `i` is its parent in the tree. The root's parent is
 *         itself. Unreachable vertices have a parent of -1.
 */
parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();

  // The parent array stores the result. Using atomics allows for thread-safe,
  // lock-free updates from parallel threads. Unvisited vertices are marked with -1.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) {
    return -1;
  });
  parent[start].store(start);
  t.next("initialize");

  // `edge_fa` is the update function. It atomically attempts to set the parent
  // of vertex `v` to `u`. It succeeds only if `v` was previously unvisited.
  // This compare-and-swap is the core of the race-free visitation logic.
  auto edge_fa = [&](vertexId u, vertexId v) -> bool {
    vertexId expected = -1;
    return parent[v].compare_exchange_strong(expected, u);
  };

  // `cond_f` is the condition function. It returns true if a vertex has not yet been visited.
  // This prevents exploring from nodes that have already been settled in the BFS tree.
  auto cond_f = [&](vertexId v) { return parent[v].load() == -1; };

  // The edge_map object encapsulates the direction-optimizing logic.
  auto frontier_map = ligra::edge_map(G, edge_fa, cond_f, verbose);

  // The initial frontier contains only the start vertex.
  auto frontier = ligra::vertex_subset(start);
  t.next("setup");

  // Main BFS loop: continues as long as the frontier is not empty.
  while (frontier.size() > 0) {
    frontier = frontier_map(frontier);
    t.next("iteration");
  }

  // Convert the atomic parent array to a regular sequence for the final result.
  return parlay::map(parent, [](auto const &x) { return x.load(); });
}
