        auto offsets = parlay::sequence<edgeId>(n + 1, 0);
        auto edge_targets = parlay::sequence<vertexId>();
        return Graph(std::move(offsets), std::move(edge_targets), n);
    }

    // Find the start of each vertex's adjacency list in the sorted edge array.
    auto flags = parlay::tabulate(m, [&](size_t i) {
        return (i == 0) || (edges[i].u != edges[i - 1].u);
    });
    auto starts = parlay::pack_index(flags);
    auto degs = parlay::sequence<std::pair<vertexId, edgeId>>::uninitialized(starts.size());
    parlay::parallel_for(0, starts.size(), [&](size_t i) {
        degs[i] = std::make_pair(edges[starts[i]].u, starts[i]);
    });

    auto offsets = parlay::sequence<edgeId>(n + 1, m);
    parlay::parallel_for(0, degs.size(), [&](size_t i) {
        offsets[degs[i].first] = degs[i].second;
    });

    // Propagate offsets for vertices with 0 degree.
    // A backwards scan finds the last non-zero-degree vertex's offset and propagates it.
    parlay::scan_inplace(parlay::make_slice(offsets).rbegin(), parlay::make_slice(offsets).rend(), parlay::minm<edgeId>());

    auto edge_targets = parlay::map(edges, [](const auto& e) { return e.v; });
    return Graph(std::move(offsets), std::move(edge_targets), n);
}

// Transposes a graph G. This is essential for a correct and efficient
// pull-based (bottom-up) BFS on directed graphs.
Graph transpose_graph(const Graph& G) {
    size_t n = G.numVertices();
    size_t m = G.numEdges();

    // Create a list of edges, but transposed (v, u) instead of (u, v).
    auto edges = parlay::sequence<edge<vertexId>>(m);
    parlay::parallel_for(0, n, [&](size_t u) {
        size_t offset = G.get_offsets()[u];
        size_t degree = G[u].degree;
        const vertexId* neighbors = G[u].Neighbors;
        for (size_t i = 0; i < degree; i++) {
            edges[offset + i] = edge<vertexId>(neighbors[i], u);
        }
    });

    // Sort edges by the new source vertex (original destination).
    parlay::sort_inplace(edges, [](const auto& a, const auto& b) {
        return a.u < b.u;
    });

    return graph_from_sorted_edges(edges, n);
}


// **************************************************************
//    A CORRECT AND OPTIMIZED LIGRA-STYLE EDGE_MAP
// **************************************************************

// This namespace contains a corrected and optimized implementation of the
// hybrid push/pull (top-down/bottom-up) graph traversal primitive.
namespace optimized_ligra {

template<typename vertexId>
using vertex_subset = ligra::vertex_subset<vertexId>;

template<typename Graph, typename Fa, typename Cond> 
struct edge_map {
  using vertexId = typename Graph::vertexId;
  using vertex_subset_ = vertex_subset<vertexId>;
  using sparse_t = parlay::sequence<vertexId>;
  using dense_t = parlay::sequence<bool>;

  Fa fa;
  Cond cond;
  const Graph& G;
  const Graph& G_T; // Transposed graph for pull phase
  bool verbose;

  edge_map(const Graph& G, const Graph& G_T, Fa fa, Cond cond, bool verbose=false) :
    G(G), G_T(G_T), fa(fa), cond(cond), verbose(verbose) {}

  // PUSH-based (top-down) traversal. Efficient for small frontiers.
  // Iterates over the current frontier and "pushes" updates to neighbors.
  auto edge_map_sparse(sparse_t const &frontier) {
    if (verbose) std::cout << "edge map sparse (push): " << frontier.size() << std::endl;

    auto nested_nghs = parlay::map(frontier, [&](vertexId u) {
      auto vtx = G[u];
      // Filter out neighbors that do not satisfy the condition, then apply the update function.
      // The update function `fa` returns true if the vertex was successfully visited.
      return parlay::delayed_filter_map(parlay::make_slice(vtx.Neighbors, vtx.Neighbors + vtx.degree),
                                        [&, u](vertexId v) { return cond(v) && fa(u, v); },
                                        [](vertexId v) { return v; });
    });

    // Flatten the sequence of sequences of new vertices into the next frontier.
    // Duplicates may exist but are handled by the atomic `parent` array updates.
    return vertex_subset_(parlay::flatten(nested_nghs));
  }

  // PULL-based (bottom-up) traversal. Efficient for large frontiers.
  // Iterates over all unvisited vertices and "pulls" updates from their
  // in-neighbors, checking if any are in the current frontier.
  // This requires the transposed graph G_T.
  auto edge_map_dense(dense_t const &frontier) {
    if (verbose) std::cout << "edge map dense (pull): " << parlay::count(frontier, true) << std::endl;

    auto next_frontier = parlay::tabulate(G.numVertices(), [&](vertexId v) -> bool {
      if (!cond(v)) return false; // Already visited, do nothing.

      auto in_neighbors = G_T[v];
      for (size_t i = 0; i < in_neighbors.degree; ++i) {
        vertexId u = in_neighbors.Neighbors[i];
        if (frontier[u]) {
          // Found an in-neighbor `u` in the frontier. Try to visit `v`.
          if (fa(u, v)) {
            return true; // Successfully visited, add to next frontier.
          }
          // If CAS fails, another thread has already visited `v` from another parent.
          // In either case, we can stop checking in-neighbors for `v`.
          break; 
        }
      }
      return false;
    });
    return vertex_subset_(std::move(next_frontier));
  }

  // The main operator that decides whether to use push or pull.
  auto operator() (vertex_subset_ const &frontier) {
    parlay::internal::timer t("edge_map", verbose);
    size_t frontier_size = frontier.size();
    size_t n = G.numVertices();

    if (frontier.is_sparse) {
      // Heuristic to switch from sparse (push) to dense (pull).
      // If the number of vertices in the frontier plus their total outgoing
      // degree is large, a pull-based approach is likely more efficient.
      auto out_degrees = parlay::delayed_map(frontier.sparse, [&](size_t i) { return G[i].degree; });
      size_t frontier_edges = parlay::reduce(out_degrees);

      if ((frontier_size + frontier_edges) > G.numEdges() / 20) {
        // Convert to dense and run pull-based traversal
        auto dense_frontier = parlay::sequence<bool>(n, false);
        parlay::parallel_for(0, frontier_size, [&](size_t i) {
          dense_frontier[frontier.sparse[i]] = true;
        });
        t.next("convert_to_dense");
        return edge_map_dense(dense_frontier);
      } else {
        return edge_map_sparse(frontier.sparse);
      }
    } else { // Frontier is dense
      // Heuristic to switch from dense (pull) to sparse (push).
      // If the frontier is no longer dense enough, switch back to push.
      if (frontier_size < n / 24) {
        // Convert to sparse and run push-based traversal
        auto sparse_frontier = parlay::pack_index<vertexId>(frontier.dense);
        t.next("convert_to_sparse");
        return edge_map_sparse(sparse_frontier);
      } else {
        return edge_map_dense(frontier.dense);
      }
    }
  }
};

} // namespace optimized_ligra
} // anonymous namespace


// **************************************************************
//    Parallel Breadth-First Search Implementation
// **************************************************************

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();

  // The parent array stores the BFS tree. `parent[i]` is the parent of vertex `i`.
  // We use atomics to allow for thread-safe, lock-free updates from multiple
  // threads visiting the same vertex concurrently.
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) {
    return -1;
  });
  parent[start] = start;
  t.next("initialize_parent_array");

  // For a correct and fast pull-based (bottom-up) traversal on directed
  // graphs, we need access to in-edges. We pre-compute the transposed graph.
  // The overhead of transposition is usually offset by the significant speedup
  // of the pull phase on graphs with large frontiers.
  Graph G_T = transpose_graph(G);
  t.next("transpose_graph");

  // The frontier of the BFS, initialized with the start vertex.
  // We use a sparse representation (list of vertex IDs) initially.
  auto frontier = optimized_ligra::vertex_subset<vertexId>(parlay::sequence<vertexId>(1, start));

  // The update function `fa(u, v)` is called for an edge u -> v.
  // It attempts to set `u` as the parent of `v`.
  // It returns true on success (i.e., v was unvisited), false otherwise.
  auto edge_fa = [p = parent.data()] (vertexId u, vertexId v) -> bool {
    vertexId expected = -1;
    // Atomic compare-and-swap ensures that only the first thread to reach
    // a vertex successfully claims it.
    return p[v].compare_exchange_strong(expected, u, std::memory_order_relaxed);
  };

  // The condition function `cond(v)` checks if a vertex `v` is unvisited.
  auto cond_f = [p = parent.data()] (vertexId v) { return p[v].load(std::memory_order_relaxed) == -1; };

  // Create the hybrid traversal engine.
  auto frontier_map = optimized_ligra::edge_map(G, G_T, edge_fa, cond_f, verbose);

  // Main BFS loop: process frontiers until empty.
  while (frontier.size() > 0) {
    frontier = frontier_map(frontier);
    t.next("iteration");
  }

  // Convert the atomic parent array to a regular sequence for the output.
  return parlay::map(parent, [](const auto& x) { return x.load(); });
}
